screen_content__adas_main_description = TextObject(de_DE="We have the ambition to enhance driving safety by provision of optimized ADAS functions , which serve directly towards the\nusers. By tapping accept, you agree to support us to realize the targets by collecting and processing the data within your\nvehicle. The decline of collection and processing of aforesaid data will not impair your use of ADAS functions. This includes\nyour general personal information as well as various technical data required only to optimize the ADAS functions. If you no\nlonger want these data to be collected and processed, you can always change your preference in the general driver\nassistance systems settings.")
screen_content__adas_sensitive_description = TextObject(de_DE="To provision of optimized ADAS functions, we would also need to collect and process your sensitive personal information\nwhich includes the data listed as below, as permitted by Person Information Protection Law of PRC. We will take security\nmeasures required by laws and regulations to protect the sensitive personal information. If you would like to grant us the\nconsent to collect and process, please tap the accept button. You can also apply an expiration time for your consent. It is 12\nmonths by default.")
screen_content__camera_description = TextObject(de_DE="In order to use ADAS relevant functions in a holistic way, please manually switch ON the Driver monitor Camera by tap\nthe “Accept”. During the activation period you can always switch off the Driver Monitor Camera which is located in the\nADAS setting page.")
screen_content__connect_device = TextObject(bs_BA="Da li po završetku želite povezati svoj telefon?", cs_CZ="Chcete následně připojit svůj telefon?", da_DK="Vil du efterfølgende forbinde din telefon?", de_DE="Möchtest du im Anschluss dein Telefon verbinden?", el_GR="Θέλετε στη συνέχεια να συνδέσετε το τηλέφωνό σας;", en_GB="Would you like to connect your phone afterwards?", es_ES="¿Desea conectar su teléfono a continuación?", fi_FI="Haluatko sitten yhdistää puhelimesi?", fr_FR="Souhaitez-vous ensuite connecter votre téléphone?", hr_HR="Želite li u nastavku spojiti svoj telefon?", hu_HU="Szeretné ezután csatlakoztatni a telefont?", it_IT="Collegare il telefono alla fine?", nl_NL="Wil je hierna je telefoon verbinden?", no_NO="Vil du opprette forbindelse med telefonen din etterpå?", pl_PL="Czy chcesz na koniec połączyć telefon?", pt_PT="No final, queres ligar o teu telefone?", ro_RO="Doriţi să conectaţi apoi telefonul?", ru_RU="Хотите ли вы потом подключить телефон?", sk_SK="Chcete pripojiť váš telefón?", sl_SI="Ali želite nato povezati svoj telefon?", sr_RS="Da li nakon toga želite da povežete svoj telefon?", sv_SE="Vill du ansluta din telefon efteråt?", tr_TR="Ardından telefonunu bağlamak ister misin?", uk_UA="Чи хочете ви потім підключити телефон?")
screen_content__finish = TextObject(bs_BA="Čestitamo, %1! Želimo Vam mnogo zabave uz Vaš Audi.", cs_CZ="Srdečně blahopřejeme, %1! Přejeme Vám s Vaším vozem Audi hodně potěšení.", da_DK="Tillykke, %1! God fornøjelse med din Audi.", de_DE="Herzlichen Glückwunsch, %1! Viel Vergnügen mit deinem Audi.", el_GR="Θερμά συγχαρητήρια, %1! Καλή διασκέδαση με το Audi σας.", en_GB="Congratulations, %1! Enjoy your Audi!", es_ES="¡Enhorabuena, %1! Disfrute de su Audi.", fi_FI="Onnea, %1! Mukavia hetkiä Audin parissa.", fr_FR="Toutes nos félicitations %1! Nous vous souhaitons beaucoup de plaisir avec votre\nAudi.", hr_HR="Čestitamo , %1! Želimo vam puno zadovoljstva s vašim Audijem.", hu_HU="Gratulálunk, %1! Használd örömmel Audi gépkocsidat!", it_IT="Congratulazioni, %1! Buon divertimento con la Sua Audi.", nl_NL="Gefeliciteerd, %1! Veel plezier met je Audi.", no_NO="Gratulerer, %1! God tur i din Audi.", pl_PL="Gratulacje, %1! Życzymy Ci dużo zadowolenia z Twojego Audi.", pt_PT="Parabéns, %1! Diverte-te com o teu Audi.", ro_RO="Felicitări, %1! Bucuraţi-vă de modelul dumneavoastră Audi.", ru_RU="Поздравляем, %1! Наслаждайтесь своим Ауди.", sk_SK="Srdečná gratulácia, %1! Zabávajte sa s vašim Audi.", sl_SI="Iskrene čestitke, %1! Obilo zabave z vašim vozilom Audi.", sr_RS="Čestitamo, %1! Mnogo zabave uz vaš Audi.", sv_SE="Grattis, %1! Ha det så kul med din Audi.", tr_TR="Tebrikler, %1! Audin ile iyi eğlenceler.", uk_UA="Вітаємо, %1! Насолоджуйтеся своїм Ауді.")
screen_content__ftw_cbl = TextObject(de_DE="Rufe %1 auf und melde dich an.\nGib dann folgenden Code ein: %2", en_GB="Go to %1 and sign in. Then\nenter this code: %2", es_ES="Ve a %1 e inicia sesión. Luego\nintroduce este código: %2", fr_FR="Rendez-vous sur %1 et\nconnectez-vous. Saisissez ensuite ce code :\n%2", it_IT="Visita la pagina %1 e accedi.\nQuindi inserisci questo codice:%2")
screen_content__ftw_error = TextObject(bs_BA="Prilikom uređivanja opcije Alexa je došlo do problema. Pokušajte aktualizirati aplikaciju Alexa u trgovini.", cs_CZ="Při nastavování Alexy se vyskytl problém. Zkuste prosím aktualizovat aplikaci Alexa ve Storu.", da_DK="Fejl opstået ved indstilling af Alexa. Forsøg at opdatere Alexa-app i store.", de_DE="Bei der Einrichtung von Alexa ist ein Problem aufgetreten. Bitte versuche, die\nAlexa App im Store zu aktualisieren.", el_GR="Κατά τη ρύθμιση της Alexa προέκυψε πρόβλημα. Προσπαθήστε να ενημερώσετε την εφαρμογή της Alexa στο Store.", en_GB="A problem occurred while setting up Alexa. Please try to update the Alexa app in the store.", es_ES="Error al configurar Alexa. Por favor, intente actualizar la App de Alexa en la Store.", fi_FI="Alexan käyttöönotossa ilmeni virhe. Yritä päivittää Alexa-sovellus Storen kautta.", fr_FR="Un problème est apparu durant la configuration d'Alexa. Veuillez essayer de mettre à jour l'application Alexa dans le Store.", hr_HR="Kod uređivanja Alexe nastupio je problem. Pokušajte aktualizirati aplikaciju Alexa u Storeu.", hu_HU="Az Alexa beállításánál probléma történt. Kérünk, próbáld meg frissíteni az Alexa alkalmazást az áruházban.", it_IT="Durante la configurazione di Alexa si è verificato un problema. Provare ad aggiornare l'app Alexa nello Store.", nl_NL="Bij het instellen van Alexa is een probleem opgetreden. Probeer de Alexa-app in de store te actualiseren.", no_NO="Det oppsto et problem ved konfigureringen av Alexa. Prøv å oppdatere Alexa-appen i appbutikken.", pl_PL="Podczas konfigurowania funkcji Alexa wystąpił problem. Spróbuj zaktualizować aplikację Alexa w sklepie.", pt_PT="Ocorreu um problema na instalação de Alexa.Por favor, tenta atualizar a aplicação Alexa na loja.", ro_RO="La configurarea Alexa a apărut o eroare. Încercaţi să actualizaţi aplicaţia Alexa în Magazin.", ru_RU="Во время настройки Alexa возникла проблема. Попробуйте обновить приложение Alexa в магазине.", sk_SK="Pri nastavovaní Alexy sa vyskytol problém. Prosím, pokúste sa aktualizovať aplikáciu Alexa v Store.", sl_SI="Pri nastavitvi Alexe je prišlo do težave. Aplikacijo Alexa poskusite posodobiti v trgovini.", sr_RS="Prilikom uređivanja aplikacije Alexa došlo je do greške. Pokušajte ažurirati aplikaciju Alexa u prodavnici.", sv_SE="Ett fel uppstod när Alexa skulle konfigureras. Försök uppdatera Alexa-appen i Store.", tr_TR="Alexa'nın kurulumu sırasında bir sorun oluştu. Lütfen Alexa uygulamasını mağazadan güncellemeyi dene.", uk_UA="Під час налаштування Alexa виникла проблема. Спробуйте оновити програму Alexa в магазині.")
screen_content__ftw_intro_text = TextObject(de_DE="Mach das Beste aus deiner Autofahrt – ganz\neinfach per Sprachbefehl. Alexa liefert\nWegbeschreibungen, spielt Musik, tätigt\nAnrufe und vieles mehr.", en_GB="Use voice to make the most of your drive.\nAlexa can help with directions, music, calls and\nmuch more.", es_ES="Usa la voz para sacar el máximo partido a tu\ntrayecto. Alexa puede ayudarte con\nindicaciones, música, llamadas y mucho más.", fr_FR="Utilisez votre voix pour profiter au mieux de\nvotre trajet. Alexa peut vous aider avec\nl'itinéraire, la musique, les appels et bien plus.", it_IT="Usa la voce per sfruttare al meglio il tempo\nche passi in auto. Alexa può aiutarti con\nindicazioni stradali, musica, chiamate e molto\naltro ancora.")
screen_content__ftw_successful_login = TextObject(bs_BA="Uspješno ste se prijavili u Amazon! Otvorite aplikaciju za pokretanje opcije Alexa.", cs_CZ="Úspěšně jste se přihlásili do Amazonu! Otevřete aplikaci, abyste spustili Alexu.", da_DK="Du blev logget korrekt på Amazon! Åbn appen for at starte Alexa.", de_DE="Du hast dich erfolgreich bei Amazon eingeloggt! Öffne die App, um Alexa zu\nstarten.", el_GR="Συνδεθήκατε επιτυχώς με την Amazon! Ανοίξτε την εφαρμογή για να ξεκινήσετε την Alexa.", en_GB="You have logged into Amazon successfully. Open the app to start Alexa.", es_ES="¡Ha iniciado sesión en Amazon correctamente! Abra la aplicación para iniciar Alexa.", fi_FI="Kirjautuminen Amazoniin on onnistunut! Avaa sovellus käynnistääksesi Alexan.", fr_FR="Vous vous êtes connecté avec succès à Amazon! Ouvrez l'application pour lancer Alexa.", hr_HR="Uspješno ste se logirali u Amazonu! Otvorite aplikaciju kako biste pokrenuli Alexu.", hu_HU="Sikeresen bejelentkeztél az Amazonra! Nyisd meg az alkalmazást az Alexa elindításához.", it_IT="Il login ad Amazon è stato eseguito correttamente! Aprire l'app per avviare Alexa.", nl_NL="Je hebt succesvol bij Amazon ingelogd! Open de app om Alexa te starten.", no_NO="Du er logget på Amazon. Åpne appen for å starte Alexa.", pl_PL="Nastapiło pomyślne zalogowanie w Amazon! Aby uruchomić funkcję Alexa, otwórz aplikację.", pt_PT="Fizeste login com sucesso em Amazon! Abre a aplicação para iniciar Alexa.", ro_RO="V-aţi autentificat cu succes la Amazon! Deschideţi aplicaţia, pentru a porni Alexa.", ru_RU="Вы успешно вошли в систему Amazon! Откройте приложение, чтобы запустить Alexa.", sk_SK="Úspešne ste sa prihlásili do Amazonu! Na spustenie Alexy otvorte aplikáciu.", sl_SI="Uspešno ste se prijavili v storitev Amazon! Za zagon Alexe odprite aplikacijo.", sr_RS="Uspešno ste se prijavili u Amazon! Otvorite aplikaciju za pokretanje opcije Alexa.", sv_SE="Du har loggat in hos Amazon. Öppna appen för att starta Alexa.", tr_TR="Başarıyla Amazon'a giriş yaptın! Alexa'yı başlatmak için uygulamayı aç.", uk_UA="Ви успішно увійшли в систему Amazon! Відкрийте програму, щоб запустити Alexa.")
screen_content__mdk_introduction_description_1 = TextObject(de_DE="Mit diesem Audi connect Dienst wird dein Smartphone zum vollwertigen\nFahrzeugschlüssel.\n\nDas Fahrzeug kann mit dem digitalen Schlüssel entriegelt, verriegelt und\ngestartet werden.")
screen_content__mdk_introduction_description_2 = TextObject(bs_BA="Za uređivanje digitalnog ključa je neophodna verifikacija od strane vašeg Audi\npartnera. Dodatne preduslove za povezivanje osnovnog uređaja možete pronaći u\nmyAudi aplikaciji.", cs_CZ="Pro nastavení digitálního klíče je nutné ověření partnerem Audi. Další požadavky na\npřipojení hlavní jednotky naleznete v aplikaci myAudi.", da_DK="For at kunne konfigurere den digitale nøgle er det nødvendigt med en verificering\nfra din Audi partner. Du kan finde yderligere forudsætninger for oprettelse af\nforbindelse for primært apparat i myAudi-appen.", de_DE="Um den digitalen Schlüssel einrichten zu können, ist eine Verifizierung durch deinen\nAudi Partner erforderlich. Weitere Voraussetzungen für die Hauptgerätverbindung\nfindest du in der myAudi App.", el_GR="Για να μπορέσει να γίνει η ρύθμιση του ψηφιακού κλειδιού, απαιτείται η επαλήθευση\nταυτότητας από τον εξουσιοδοτημένο συνεργάτη Audi που σας εξυπηρετεί. Σχετικά με\nτις περαιτέρω προϋποθέσεις για τη σύνδεση της βασικής συσκευής θα ενημερωθείτε\nστην εφαρμογή myAudi.", en_GB="In order to set up the digital key, verification by your Audi Partner is required. You\nwill find further requirements for connecting the main device in the myAudi app.", es_ES="Para poder configurar la llave digital se precisa una verificación por parte de su\nConcesionario Audi . Encontrará el resto de requisitos para la conexión del\ndispositivo principal en la App myAudi.", fi_FI="Digitaalisen avaimen muodostaminen edellyttää Audi-jälleenmyyjäsi tekemää\nvarmennusta. Muut päälaitteen yhdistämisen edellytykset löytyvät\nmyAudi-sovelluksesta.", fr_FR="Pour pouvoir configurer la clé numérique, une vérification par votre Partenaire Audi\nest nécessaire. Vous trouverez d'autres conditions préalables pour la connexion du\npériphérique principal dans l'application myAudi.", hr_HR="Kako biste uredili digitalni ključ, potrebna je verifikacija od strane Audi partnera.\nOstale preduvjete za spajanje glavnog uređaja možete pronaći u myAudi aplikaciji.", hu_HU="A digitális kulcs beállításához Audi partnerednek ellenőrzést kell végeznie. A\nfőkészülék csatlakoztatásának további feltételeit a myAudi alkalmazásban\ntalálhatod meg.", it_IT="Per poter configurare la chiave digitale è necessaria una verifica da parte del partner\nAudi. Gli ulteriori requisiti per il collegamento del dispositivo principale sono\ndisponibili nell'app myAudi.", nl_NL="Om de digitale sleutel in te stellen is verificatie door jouw Audi-partner vereist.\nMeer vereisten voor de aansluiting van het hoofdapparaat vind je in de myAudi-app.", no_NO="Du må verifisere deg hos Audi-forhandleren for å kunne sette opp den digitale\nnøkkelen. Du finner flere forutsetninger for å opprette forbindelse med en\nhovedenhet i myAudi-appen.", pl_PL="Aby skonfigurować klucz cyfrowy, wymagana jest weryfikacja przez dealera Audi.\nDodatkowe warunki podłączenia urządzenia głównego można znaleźć w aplikacji\nmyAudi.", pt_PT="Para poderes configurar a chave digital é necessário que o teu Concessionário Audi\nfaça uma verificação. Podes consultar mais requisitos para a ligação ao aparelho\nprincipal na myAudi app.", ro_RO="Pentru a putea configura cheia digitală, este necesară o verificare de către\npartenerul Audi. Premise suplimentare pentru conectarea dispozitivului principal\ngăsiţi în aplicaţia myAudi.", ru_RU="Для установки цифрового ключа требуется верификация у партнера Audi.\nДополнительные требования к подключению основного устройства можно\nнайти в приложении myAudi.", sk_SK="Aby ste mohli nastaviť digitálny kľúč, je potrebné overenie partnerom Audi. Ďalšie\npredpoklady na pripojenie hlavného zariadenia nájdete v aplikácii myAudi.", sl_SI="Za nastavitev digitalnega ključa je potrebno preverjanje pristnosti, ki ga opravi vaš\npooblaščeni partner Audi. Dodatne pogoje za povezavo glavne naprave najdete v\naplikaciji myAudi.", sr_RS="Da biste mogli urediti digitalni ključ, neophodna je verifikacija od strane vašeg Audi\npartnera. Ostale preduslove za povezivanje osnovnog uređaja možete pronaći u\naplikaciji myAudi.", sv_SE="För att kunna ställa in den digitala nyckeln krävs verifiering via din Audi-partner.\nFler villkor för att ansluta en huvudenhet hittar du i myAudi-appen.", tr_TR="Dijital anahtarın kurulumu için Audi yetkili servisin tarafından doğrulama yapılması\ngerekmektedir. Ana cihaz bağlantısına ilişkin diğer gereksinimleri myAudi\nuygulamasında bulabilirsin.", uk_UA="Для налаштування цифрового ключа необхідна перевірка вашого партнера\nAudi. Інші вимоги до підключення основного пристрою можна знайти в програмі\nmyAudi.")
screen_content__mdk_key_not_successful_description = TextObject(bs_BA="Uređivanje osnovnog uređaja, na žalost, nije bilo moguće zbog tehničke greške. Pokušajte ponovo kasnije preko myAudi\naplikacije.", cs_CZ="Hlavní jednotku bohužel nebylo možné nastavit kvůli technické chybě. Zkuste to prosím později znovu prostřednictvím\naplikace myAudi.", da_DK="Primært apparat kunne ikke konfigureres på grund af en teknisk fejl. Forsøg igen senere via myAudi-appen.", de_DE="Das Hauptgerät konnte aufgrund eines technischen Fehlers leider nicht eingerichtet werden. Bitte versuche es später\nerneut über die myAudi App.", el_GR="Η ρύθμιση της βασικής συσκευής δεν ήταν εφικτή εξαιτίας ενός τεχνικού σφάλματος. Προσπαθήστε πάλι αργότερα μέσω\nτης εφαρμογής myAudi.", en_GB="Unable to configure main device due to a technical error. Please try again later via the myAudi app.", es_ES="El dispositivo principal no se ha podido configurar por un fallo técnico. Por favor, inténtelo de nuevo más tarde con la\nApp myAudi.", fi_FI="Päälaitetta ei voitu muodostaa teknisen virheen vuoksi. Yritä myöhemmin uudelleen myAudi-sovelluksessa.", fr_FR="Le périphérique principal n'a malheureusement pas pu être configuré en raison d'une erreur technique. Veuillez\nréessayer ultérieurement via l'application myAudi.", hr_HR="Glavni uređaj zbog tehničke greške na žalost nije bilo moguće urediti. Pokušajte ponovno kasnije preko myAudi\naplikacije.", hu_HU="Sajnos a főkészüléket műszaki hiba miatt nem sikerült beállítani. Próbáld újra később a myAudi alkalmazással.", it_IT="Non è stato possibile configurare il dispositivo principale a causa di un errore tecnico. Si prega di riprovare più tardi\ntramite l'app myAudi.", nl_NL="Helaas kon het hoofdapparaat vanwege een technische fout niet worden ingesteld. Probeer het later opnieuw via de\nmyAudi-app.", no_NO="Kan ikke sette opp hovedenheten på grunn av en teknisk feil. Prøv igjen i myAudi-appen senere.", pl_PL="Niestety, nie można skonfigurować urządzenia głównego z powodu błędu technicznego. Spróbuj ponownie później za\npomocą aplikacji myAudi.", pt_PT="Devido a uma falha técnica, infelizmente não é possível configurar o aparelho principal. Por favor, volta a tentar mais\ntarde através da myAudi app.", ro_RO="Dispozitivul principal nu a putut fi configurat din cauza unei erori tehnice. Reîncercaţi mai târziu prin aplicaţia myAudi.", ru_RU="К сожалению, основное устройство не удалось настроить из-за технической ошибки. Пожалуйста, повторите\nпопытку позже через приложение myAudi.", sk_SK="Žiaľ, hlavnú jednotku nie je možné nastaviť z dôvodu technickej chyby. Prosím, pokúste sa o to znovu neskôr\nprostredníctvom aplikácie myAudi.", sl_SI="Glavne naprave zaradi tehnične napake žal ni bilo mogoče nastaviti. Poskusite znova pozneje v aplikaciji myAudi.", sr_RS="Uređivanje osnovnog uređaja, na žalost, nije bilo moguće zbog tehničke greške. Pokušajte ponovo kasnije preko aplikacije\nmyAudi.", sv_SE="Huvudenheten kunde tyvärr inte konfigureras på grund av ett tekniskt fel. Försök igen senare via myAudi-appen.", tr_TR="Ne yazık ki teknik bir hata nedeniyle ana cihaz kurulamadı. Lütfen daha sonra myAudi uygulaması üzerinden tekrar dene.", uk_UA="На жаль, основний пристрій не вдалося налаштувати через технічну помилку. Будь ласка, спробуйте пізніше через\nпрограму myAudi.")
screen_content__mdk_key_not_successful_title = TextObject(bs_BA="Neuspješno uređivanje digitalnog ključa", cs_CZ="Nepodařilo se nastavit digitální klíč", da_DK="Konfigurering af digital nøgle mislykkedes.", de_DE="Einrichten des digitalen Schlüssels fehlgeschlagen", el_GR="Η ρύθμιση του ψηφιακού κλειδιού απέτυχε", en_GB="Setup of digital key failed", es_ES="Error al configurar la llave digital", fi_FI="Digitaalisen avaimen muodostaminen epäonnistui", fr_FR="Échec de la configuration de la clé numérique", hr_HR="Uređivanje digitalnog ključa nije uspjelo", hu_HU="A digitális kulcs beállítása sikertelen", it_IT="Configurazione della chiave digitale non riuscita", nl_NL="Instellen van de digitale sleutel is mislukt", no_NO="Oppsett av den digitale nøkkelen mislyktes", pl_PL="Konfigurowanie klucza cyfrowego nie powiodło się", pt_PT="Configuração da chave digital falhou", ro_RO="Configurarea cheii digitale a eşuat", ru_RU="Не удалось настроить цифровой ключ", sk_SK="Nastavenie digitálneho kľúča sa nepodarilo", sl_SI="Nastavitev digitalnega ključa ni uspela", sr_RS="Neuspešno uređivanje digitalnog ključa", sv_SE="Inställningen av den digitala nyckeln misslyckades", tr_TR="Dijital anahtarın kurulumu başarısız oldu", uk_UA="Не вдалося налаштувати цифровий ключ")
screen_content__mdk_key_successful_description = TextObject(de_DE="Du kannst deinen digitalen Schlüssel jetzt als vollwertigen Fahrzeugschlüssel zum Entriegeln,\nVerriegeln und Starten des Fahrzeugs verwenden.")
screen_content__mdk_key_successful_not_tracked__description = TextObject(bs_BA="Provjerite na svom pametnom telefonu možete li ga koristiti kao digitalni ključ. Uvjerite se da\nvaš pametni telefon ima aktivnu internet vezu.", cs_CZ="Na svém smartphonu prosím zkontrolujte, zda ho můžete používat jako digitální klíček.\nZkontrolujte, že má Váš smartphone aktivní připojení k internetu.", da_DK="Kontroller på din smartphone, om du kan anvende den som digital nøgle. Kontroller i den\nforbindelse, at din smartphone har en aktiv internetforbindelse.", de_DE="Bitte überprüfe auf deinem Smartphone, ob du es als digitalen Schlüssel verwenden kannst.\nStelle dazu sicher, dass dein Smartphone eine aktive Internetverbindung hat.", el_GR="Ελέγξτε στο smartphone σας, αν μπορείτε να το χρησιμοποιήσετε ως ψηφιακό κλειδί. Για τον\nσκοπό αυτό βεβαιωθείτε ότι το smartphone σας διαθέτει ενεργή σύνδεση με το διαδίκτυο.", en_GB="Please check on your smartphone whether it can be used as a digital key. You should also ensure\nthat it has an active Internet connection.", es_ES="Compruebe en su smartphone si puede utilizarlo como llave digital. Asegúrese de que el\nsmartphone tiene conexión a Internet.", fi_FI="Tarkasta älypuhelimesta, voidaanko sitä käyttää digitaalisena avaimena. Varmista sitä varten,\nettä älypuhelimella on aktiivinen internet-yhteys.", fr_FR="Veuillez vérifier sur votre smartphone si vous pouvez l'utiliser en tant que clé numérique.\nAssurez-vous à cet effet que votre smartphone dispose d'une connexion Internet active.", hr_HR="Provjerite na svom smartphoneu da li ga možete koristiti kao digitalni ključ. U tu svrhu vaš\nsmartphone mora imat i aktivnu internetsku vezu.", hu_HU="Kérünk, ellenőrizd okostelefonodat, hogy használható-e digitális kulcsként. Ehhez győződj meg\nróla, hogy okostelefonod rendelkezik aktív internetkapcsolattal.", it_IT="Controllare sullo smartphone se è possibile utilizzarlo come chiave digitale. Accertarsi che lo\nsmartphone abbia un collegamento internet attivo.", nl_NL="Controleer op je smartphone of je deze als digitale sleutel kunt gebruiken. Zorg er daarnaast\nvoor dat je smartphone een actieve internetverbinding heeft.", no_NO="Kontroller på smarttelefonen om du kan bruke den som digital nøkkel. Når du gjør det, må\nsmarttelefonen ha internettforbindelse.", pl_PL="Sprawdź w swoim smartfoonie, czy możesz go używać jako kluczyka cyfrowego. W tym celu\nupewnij się, że Twój smartfon ma aktywne połączenie z Internetem.", pt_PT="Por favor, verifica no teu smartphone se o podes utilizar como chave digital. Certifica-te que o\nteu smartphone tem uma ligação à Internet ativa.", ro_RO="Verificaţi pe smartphone-ul dumneavoastră, dacă îl puteţi utiliza ca şi cheie digitală.\nAsiguraţi-vă că smartphone-ul dumneavoastră dispune de o conexiune activă la Internet.", ru_RU="Пожалуйста, проверьте на своем смартфоне, можно ли использовать его в качестве\nцифрового ключа. Для этого убедитесь, что Ваш смартфон имеет активное\nинтернет-соединение.", sk_SK="Skontrolujte si na svojom smartfóne, či ho môžete použiť ako digitálny kľúč. K tomu sa uistite,\nže váš smartfón má aktívne internetové pripojenie.", sl_SI="Na svojem pametnem telefonu preverite, ali ga lahko uporabljate kot digitalni ključ. Poleg tega\npreverite, da ima vaš pametni telefon aktivno internetno povezavo.", sr_RS="Proverite na svom pametnom telefonu da li ga možete koristiti kao digitalni ključ. Uverite se da\nvaš pametni telefon ima aktivnu internet vezu.", sv_SE="Kontrollera på din smartphone om du kan använda den som digital nyckel. Säkerställ att din\nsmartphone har en aktiv internetanslutning.", tr_TR="Lütfen akıllı telefonunda, bunu dijital anahtar olarak kullanıp kullanamayacağını kontrol et.\nBunun için, akıllı telefonunun aktif bir internet bağlantısına sahip olduğundan emin ol.", uk_UA="Будь ласка, перевірте на своєму смартфоні, чи можна використовувати його як цифровий\nключ. Для цього переконайтеся, що ваш смартфон має активне з'єднання з Інтернетом.")
screen_content__mdk_key_successful_not_tracked_title = TextObject(bs_BA="Čestitamo vam na digitalnom ključu!", cs_CZ="Gratulujeme k Vašemu digitálnímu klíčku!", da_DK="Tillykke med din digitale nøgle!", de_DE="Glückwunsch zu deinem digitalen Schlüssel!", el_GR="Συγχαρητήρια για το ψηφιακό κλειδί σας!", en_GB="Congratulations on your digital key!", es_ES="¡Enhorabuena por su llave digital!", fi_FI="Onnittelut digitaalisesta avaimesta!", fr_FR="Félicitation pour la configuration de votre clé numérique!", hr_HR="Čestitamo vam na vašem digitalnom ključu!", hu_HU="Gratulálunk digitális kulcsodhoz!", it_IT="Congratulazioni per la Sua nuova chiave digitale!", nl_NL="Gefeliciteerd met je digitale sleutel!", no_NO="Gratulerer med den digitale nøkkelen!", pl_PL="Gratulujemy Ci kluczyka cyfrowego!", pt_PT="Parabéns pela tua chave digital!", ro_RO="Felicitări pentru cheia dumneavoastră digitală!", ru_RU="Поздравляем с получением цифрового ключа!", sk_SK="Gratulujeme k vášmu digitálnemu kľúču!", sl_SI="Čestitke za digitalni ključ!", sr_RS="Čestitamo vam na digitalnom ključu!", sv_SE="Lycka till med din digitala nyckel!", tr_TR="Dijital anahtarını kutlarız!", uk_UA="Вітаємо з отриманням цифрового ключа!")
screen_content__mdk_key_successful_title = TextObject(bs_BA="Čestitamo vam na digitalnom ključu!", cs_CZ="Gratulujeme k Vašemu digitálnímu klíčku!", da_DK="Tillykke med din digitale nøgle!", de_DE="Glückwunsch zu deinem digitalen Schlüssel!", el_GR="Συγχαρητήρια για το ψηφιακό κλειδί σας!", en_GB="Congratulations on your digital key!", es_ES="¡Enhorabuena por su llave digital!", fi_FI="Onnittelut digitaalisesta avaimesta!", fr_FR="Félicitation pour la configuration de votre clé numérique!", hr_HR="Čestitamo vam na vašem digitalnom ključu!", hu_HU="Gratulálunk digitális kulcsodhoz!", it_IT="Congratulazioni per la Sua nuova chiave digitale!", nl_NL="Gefeliciteerd met je digitale sleutel!", no_NO="Gratulerer med den digitale nøkkelen!", pl_PL="Gratulujemy Ci kluczyka cyfrowego!", pt_PT="Parabéns pela tua chave digital!", ro_RO="Felicitări pentru cheia dumneavoastră digitală!", ru_RU="Поздравляем с получением цифрового ключа!", sk_SK="Gratulujeme k vášmu digitálnemu kľúču!", sl_SI="Čestitke za digitalni ključ!", sr_RS="Čestitamo vam na digitalnom ključu!", sv_SE="Lycka till med din digitala nyckel!", tr_TR="Dijital anahtarını kutlarız!", uk_UA="Вітаємо з отриманням цифрового ключа!")
screen_content__mdk_loading_ble = TextObject(bs_BA="Proces podešavanja glavnog uređaja je u toku. Nemojte deaktivirati Bluetooth tokom\npostupka. Sačekajte...", cs_CZ="Proces vytváření hlavního zařízení probíhá. Během procesu prosím nedeaktivujte\nBluetooth. Čekejte prosím...", da_DK="Primært apparats konfigureringsproces i gang. Deaktiver ikke Bluetooth i løbet af\nprocessen. Vent...", de_DE="Der Einrichtungsprozess des Hauptgeräts läuft. Bitte Bluetooth während des Vorgangs\nnicht deaktivieren. Bitte warten...", el_GR="Η διαδικασία ρύθμισης της βασικής συσκευής είναι σε εξέλιξη. Μην απενεργοποιήσετε το\nBluetooth κατά τη διάρκεια της διαδικασίας. Παρακαλώ περιμένετε…", en_GB="Setting up the main device. Please do not deactivate Bluetooth during this process.\nPlease wait...", es_ES="Proceso de configuración del dispositivo principal en curso. No desactive el Bluetooth\ndurante el proceso. Por favor, espere...", fi_FI="Päälaitteen käyttöönottoprosessi on käynnissä. Älä deaktivoi Bluetoothia menettelyn\naikana. Odota...", fr_FR="La procédure de configuration du périphérique principal est en cours. Veuillez ne pas\ndésactiver le Bluetooth pendant la procédure. Veuillez patienter...", hr_HR="U tijeku je proces uređivanja glavnog uređaja. Nemojte deaktivirati Bluetooth tijekom\novog postupka. Čekajte...", hu_HU="A főkészülék beállítása folyamatban van. A Bluetooth ne legyen kikapcsolva a folyamat\nközben. Kérem, várjon...", it_IT="È in corso il processo di configurazione del dispositivo principale. Non disattivare il\nBluetooth durante l'operazione. Attendere prego...", nl_NL="Het proces voor het instellen van het hoofdapparaat is bezig. Schakel Bluetooth\ngedurende het proces niet uit. Even geduld...", no_NO="Prosessen for å sette opp hovedenhet kjører. Ikke deaktiver Bluetooth under prosessen.\nVent litt...", pl_PL="Trwa proces konfigurowania urządzenia głównego. W trakcie procesu nie wyłączaj funkcji\nBluetooth. Proszę czekać...", pt_PT="Está em curso o processo de criação do aparelho principal. Por favor, não desativar o\nBluetooth durante o procedimento. Por favor, aguardar...", ro_RO="Se execută configurarea dispozitivului principal. Nu dezactivaţi conexiunea Bluetooth pe\ndurata procesului. Aşteptaţi...", ru_RU="Идет процесс настройки основного устройства. Не выключайте Bluetooth во время\nпроцесса. Пожалуйста, ждите...", sk_SK="Prebieha proces nastavenia hlavného zariadenia. Prosím, nevypínajte Bluetooth počas\nprocesu. Čakajte, prosím...", sl_SI="Nastavitev glavne naprave poteka. Med postopkom ne deaktivirajte vmesnika Bluetooth.\nProsimo, počakajte ...", sr_RS="Proces aktiviranja glavnog uređaja je u toku. Nemojte deaktivirati Bluetooth tokom\npostupka. Sačekajte...", sv_SE="Inställningsprocessen för huvudenheten pågår. Avaktivera inte Bluetooth under\nförloppet. Vänta...", tr_TR="Ana cihazın kurulum süreci devam ediyor. Lütfen işlem sırasında Bluetooth'u\nkapatmayın. Lütfen bekleyin...", uk_UA="Триває процес налаштування основного пристрою. Не вимикайте Bluetooth під час\nпроцесу. Зачекайте...")
screen_content__mdk_loading_nfc = TextObject(bs_BA="Proces podešavanja glavnog uređaja je u toku. Tokom postupka, nemojte sklanjati\npametni telefon sa mjesta za odlaganje telefona. Sačekajte...", cs_CZ="Probíhá nastavování hlavního zařízení. Během procesu prosím neodstraňujte\nsmartphone z telefonní přihrádky. Čekejte prosím...", da_DK="Primært apparats konfigureringsproces i gang. Fjern ikke smartphone fra\nopbevaringsflade til telefon i løbet af processen. Vent...", de_DE="Der Einrichtungsprozess des Hauptgeräts läuft. Bitte Smartphone während des\nVorgangs nicht aus der Telefonablage entfernen. Bitte warten…", el_GR="Η διαδικασία ρύθμισης της βασικής συσκευής είναι σε εξέλιξη. Μην αφαιρείτε το\nsmartphone από τη θήκη απόθεσης τηλεφνου κατά τη διάρκεια της διαδικασίας.\nΠαρακαλώ περιμένετε…", en_GB="The main device is currently being set up. Please do not remove your smartphone from\nthe phone compartment during this process. Please wait…", es_ES="Proceso de configuración del dispositivo principal en curso. No retire el smartphone del\nalojamiento para el teléfono durante el proceso. Por favor, espere...", fi_FI="Päälaitteen käyttöönottoprosessi on käynnissä. Älä poista älypuhelinta puhelinlokerosta\nmenettelyn aikana. Odota...", fr_FR="La procédure de configuration du périphérique principal est en cours. Veuillez ne pas\nretirer le smartphone du compartiment pour téléphone pendant la procédure. Veuillez\npatienter...", hr_HR="Proces uređivanja glavnog uređaja je u tijeku. Tijekom postupka nemojte vaditi\nsmartphone iz pretinca za odlaganje telefona. Čekajte....", hu_HU="A főkészülék beállítása folyamatban van. Nem szabad eltávolítani az okostelefont a\ntelefontartóból a folyamat közben. Kérünk, várj...", it_IT="È in corso il processo di configurazione del dispositivo principale. Non rimuovere lo\nsmartphone dal vano per telefono durante l'operazione. Attendere prego...", nl_NL="Het instellingsproces van het hoofdapparaat wordt uitgevoerd. Haal je smartphone niet\nuit de telefoonhouder tijdens het proces. Even geduld...", no_NO="Prosessen for å sette opp hovedenhet kjører. Ikke fjern smarttelefonen fra\noppbevaringsplassen under prosessen. Vent litt...", pl_PL="Trwa proces konfigurowania urządzenia głównego. Podczas tego procesu nie należy\nwyjmować smartfona ze schowka na telefon. Proszę czekać...", pt_PT="O processo de instalação do aparelho principal está em curso. Durante este\nprocedimento não retirar o smartphone do compartimento do telefone. Por favor,\naguardar...", ro_RO="Se execută configurarea dispozitivului principal. Nu scoateţi smartphone-ul din suportul\npentru telefon pe durata procesului. Aşteptaţi...", ru_RU="Идет процесс настройки основного устройства. Не вынимайте смартфон из\nдержателя телефона во время процесса. Пожалуйста, ждите…", sk_SK="Prebieha proces nastavenia hlavného zariadenia. Prosím, v priebehu tohto procesu\nneodstraňujte svoj smartfón z odkladacieho priestoru telefónu. Čakajte, prosím...", sl_SI="Nastavitev glavne naprave poteka. Pametnega telefona med postopkom ne odstranite iz\npredala za telefon. Prosimo, počakajte ...", sr_RS="Proces aktiviranja glavnog uređaja je u toku. Tokom postupka, nemojte sklanjati pametni\ntelefon sa mesta za odlaganje telefona. Sačekajte...", sv_SE="Upprättandet av huvudenheten körs. Ta inte bort smartphone ur telefonfacket under\nförloppet. Vänta…", tr_TR="Ana cihazın kurulum süreci devam ediyor. Lütfen işlem sırasında akıllı telefonu telefon\ntepsisinden çıkarmayın. Lütfen bekleyin...", uk_UA="Триває процес налаштування основного пристрою. Не виймайте смартфон з відсіку\nдля телефону під час процесу. Зачекайте...")
screen_content__mdk_no_connection_description = TextObject(bs_BA="Jest li već instalirali myAudi aplikaciju na Vašem pametnom telefonu? U\ntom slučaju možete povezati Vaš uređaj direktno kao glavni uređaj putem\nBluetooth-a ili NFC.  Bluetooth: Provjerite da li je na Vašem uređaju\naktiviran Bluetooth i potvrdite upit.  NFC: Odložite Vaš pametni telefon na\nmjesto za odlaganje.", cs_CZ="Nainstalovali jste si již aplikaci myAudi do svého chytrého telefonu? Pak\nmůžete své zařízení připojit přímo jako hlavní zařízení prostřednictvím\nBluetooth nebo NFC.  Bluetooth: Zkontrolujte, zda je v zařízení aktivováno\nBluetooth, a potvrďte požadavek.   NFC: Umístěte váš chytrý telefon do\npřihrádky na telefon.", da_DK="Har du allerede installeret myAudi-appen på din smartphone? Så kan du\nforbinde dit apparat direkte som primært apparat via Bluetooth eller NFC. \nBluetooth: Kontroller, om Bluetooth er aktiveret på dit apparat, og\nbekræft spørgsmålet.  NFC: Placer din smartphone i telefonholderen.", de_DE="Hast du bereits die myAudi App auf deinem Smartphone installiert? Dann\nkannst du dein Gerät direkt als Hauptgerät per Bluetooth oder NFC\nverbinden.  Bluetooth: Überprüfe, ob Bluetooth auf deinem Gerät aktiviert\nist und bestätige die Anfrage.  NFC: Bitte lege dein Smartphone in die\nTelefonablage.", el_GR="Έχετε ήδη εγκαταστήσει την εφαρμογή myAudi στο smartphone σας; Τότε\nμπορείτε να συνδέσετε τη συσκευή σας απευθείας ως βασική συσκευή μέσω\nBluetooth ή NFC.  Bluetooth: Ελέγξτε αν το Bluetooth είναι ενεργοποιημένο\nστη συσκευή σας και επιβεβαιώστε το αίτημα.  NFC: Τοποθετήστε το\nsmartphone σας στη θήκη απόθεσης τηλεφώνου.", en_GB="Have you already installed the myAudi app on your smartphone? Then you\ncan connect your device directly as the main device via Bluetooth or NFC. \nBluetooth: check whether Bluetooth is activated on your device and\nconfirm the request.  NFC: please place your smartphone in the phone\ncompartment.", es_ES="¿Ha instalado ya la App myAudi en su smartphone? Entonces podrá\nconectar su dispositivo directamente como dispositivo principal por\nBluetooth o NFC.  Bluetooth: Compruebe si el Bluetooth está activado en\nsu dispositivo y confirme la pregunta.  NFC: Coloque su smartphone en el\nalojamiento para el teléfono.", fi_FI="Oletko jo asentanut myAudi-sovelluksen älypuhelimeesi? Sen jälkeen voit\nyhdistää laitteesi suoraan päälaitteena Bluetoothin tai NFC:n avulla. \nBluetooth: Tarkasta, onko Bluetooth aktivoitu laitteeltasi ja vahvista\nkysymys.  NFC: Aseta älypuhelin puhelinlokeroon.", fr_FR="Avez-vous déjà installé l'application myAudi sur votre smartphone? Vous\npourrez ensuite connecter directement votre périphérique comme\npériphérique principal via Bluetooth ou NFC.  Bluetooth: vérifiez que le\nBluetooth est activé sur votre périphérique et confirmez la demande. \nNFC: veuillez déposer votre smartphone dans le compartiment pour\ntéléphone.", hr_HR="Jeste li već instalirali myAudi aplikaciju na svom smartphoneu? Možete\nspojiti svoj uređaj direktno kao glavni uređaj preko bluetootha ili NFC-a. \nBluetooth: provjerite je li na vašem uređaju aktiviran bluetooth i potvrdite\nupit.  NFC: odložite svoj smartphone u pretinac za odlaganje telefona.", hu_HU="Telepítetted már okostelefonodra a myAudi alkalmazást? Ezzel\nközvetlenül főkészülékként csatlakoztathatod készülékedet a\nBluetooth-on vagy NFC-n keresztül.  Bluetooth: ellenőrizd, hogy a\nBluetooth aktiválva van-e a készülékeden, és erősítsd meg a kérést.  NFC:\nhelyezd okostelefonodat a telefontartóba.", it_IT="Ha già installato l'app myAudi sul Suo smartphone? Allora può collegare\ndirettamente il Suo dispositivo come dispositivo principale tramite\nBluetooth o NFC.  Bluetooth: controlli che sul Suo dispositivo sia attivato il\nBluetooth e confermi la richiesta.  NFC: riponga lo smartphone nel vano\nper telefono.", nl_NL="Heb je de myAudi-app al op je smartphone geïnstalleerd? Dan kun je je\napparaat direct als hoofdapparaat verbinden via Bluetooth of NFC. \nBluetooth: Controleer of Bluetooth op je apparaat is geactiveerd en\nbevestig het verzoek.  NFC: Plaats je smartphone in de telefoonhouder.", no_NO="Har du installert myAudi-appen på smarttelefonen? Som hovedbruker kan\ndu da opprette forbindelse med enheten ved hjelp av Bluetooth eller NFC. \nBluetooth: Kontroller at Bluetooth er aktivert på enheten, og bekreft\nforespørselen.  NFC: Legg smarttelefonen på oppbevaringsplassen for\nmobiltelefon.", pl_PL="Czy aplikacja myAudi została już zainstalowana w smartfonie? Możesz\nwówczas podłączyć swoje urządzenie bezpośrednio jako urządzenie\ngłówne przez Bluetooth lub NFC.  Bluetooth: sprawdź, czy funkcja\nBluetooth jest włączona w urządzeniu i potwierdź zapytanie.  NFC: Umieść\nsmartfon w schowku na telefon.", pt_PT="Já instalas-te a myAudi app no teu smartphone? Depois podes ligar\ndiretamente o teu aparelho como aparelho principal através de Bluetooth\nou de NFC.  Bluetooth: Verifica se o Bluetooth está tivo no teu aparelho e\nconfirma a questão.  NFC: Por favor, coloca o teu smartphone no\ncompartimento do telemóvel.", ro_RO="Aţi instalat deja pe smartphone aplicaţia myAudi? Atunci puteţi conecta\ndispozitivul direct, ca dispozitiv principal, prin Bluetooth sau NFC. \nBluetooth: verificaţi dacă Bluetooth este activat pe dispozitivul\ndumneavoastră şi confirmaţi solicitarea.  NFC: aşezaţi smartphone-ul în\nsuportul pentru telefon.", ru_RU="Если вы уже установили приложение myAudi на свой смартфон, вы\nможете подключить свое устройство непосредственно в качестве\nосновного устройства через Bluetooth или NFC.  Bluetooth: проверьте,\nактивирован ли Bluetooth на вашем устройстве, и подтвердите запрос. \nNFC: поместить смартфон в держатель телефона.", sk_SK="Nainštalovali ste si už aplikáciu myAudi do svojho smartfónu? Potom\nmôžete svoje zariadenie pripojiť priamo ako hlavné zariadenie\nprostredníctvom Bluetooth alebo NFC.  Bluetooth: skontrolujte, či je na\nvašom zariadení aktivovaná funkcia Bluetooth a potvrďte požiadavku. \nNFC: prosím, umiestnite svoj smartfón do priehradky na telefón.", sl_SI="Ali ste aplikacijo myAudi že namestili na svoj pametni telefon? Potem\nlahko svojo napravo kot glavno napravo neposredno povežete preko\nvmesnika Bluetooth ali NFC.  Bluetooth: preverite, ali je Bluetooth\naktiviran na vaši napravi, in potrdite zahtevo.  NFC: svoj pametni telefon\npoložite v predal za telefon.", sr_RS="Da li ste već instalirali aplikaciju myAudi na vaš pametni telefon? U tom\nslučaju, vaš uređaj možete da povežete direktno kao osnovni uređaj preko\nBluetooth-a ili NFC.  Bluetooth: Proverite da li je aktiviran Bluetooth na\nvašem uređaju i potvrdite zahtev.  NFC: Molimo vas da odložite pametni\ntelefon na mesto za odlaganje.", sv_SE="Har du redan installerat myAudi-appen på din smartphone? Då kan du\nansluta din enhet direkt som huvudenhet via Bluetooth eller NFC. \nBluetooth: Kontrollera att Bluetooth är aktiverat på din enhet och bekräfta\nförfrågan.  NFC: Lägg smartphonen i telefonfacket.", tr_TR="Önceden myAudi uygulamasını akıllı telefonuna yükledin mi? Ardından\ncihazını Bluetooth veya NFC üzerinden doğrudan ana cihaz olarak\nbağlayabilirsin.  Bluetooth: Cihazında Bluetooth'un etkin olup olmadığını\nkontrol et ve talebi onayla.  NFC: Lütfen akıllı telefonunu telefon tepsisine\nyerleştir.", uk_UA="Якщо на вашому смартфоні вже встановлено програму myAudi, ви\nможете підключити пристрій безпосередньо як основний пристрій\nчерез Bluetooth або NFC.  Bluetooth: перевірте, чи увімкнено Bluetooth\nна вашому пристрої, і підтвердіть запит.  NFC: покладіть смартфон у\nвідсік для телефону.")
screen_content__mdk_no_password_description = TextObject(bs_BA="Vaš pametni telefon se ne nalazi u režimu uređivanja. Pokrenite režim uređivanja u myAudi aplikaciji pod opcijom „Digitalni ključ“. Alternativno uređivanje možete pokrenuti preko poveznice koja je dostavljena glavnom korisniku. Nakon toga slijedite smjernice na Vašem pametnom telefonu.", cs_CZ="Smartphone není v režimu nastavení. Spusťte prosím režim nastavení v aplikaci myAudi v části „Digitální klíč“. Případně můžete spustit režim nastavení prostřednictvím odkazu zaslaného hlavnímu uživateli. Poté postupujte podle pokynů v smartphonu.", da_DK="Din smartphone er ikke i konfigureringsmodus. Start konfigureringsmodus i myAudi-appen under \"Digital nøgle\". Alternativt kan du starte konfigureringen via det link, som er blevet sendt til den primære bruger. Følg derefter anvisningerne på din smartphone.", de_DE="Dein Smartphone ist noch nicht im Einrichtungsmodus. Bitte starte den Einrichtungsmodus in der myAudi App unter\n„Digitaler Schlüssel“. Alternativ kannst du die Einrichtung über den Link starten, der dem Hauptnutzer zugesendet\nwurde. Folge anschließend den Anweisungen auf deinem Smartphone.", el_GR="Το smartphone σας δεν είναι σε λειτουργία ρύθμισης. Εκκινήστε τη λειτουργία ρύθμισης στην εφαρμογή myAudi στο σημείο “Ψηφιακό κλειδί”. Εναλλακτικά, μπορείτε να ξεκινήσετε τη ρύθμιση μέσω του συνδέσμου που έχει αποσταλεί  στον βασικό χρήστη. Μετά από αυτό, ακολουθήστε τις οδηγίες στο smartphone σας.", en_GB="Your smartphone is not in setup mode. Please start setup mode in the myAudi app under \"Digital key\". Alternatively, you can start setup via the link which was sent to the key user. Then follow the instructions on your smartphone.", es_ES="Su smartphone no está en modo de configuración. Inicie el modo de configuración en la App myAudi, dentro del apartado \"Llave digital\". También puede iniciar la configuración con el enlace enviado al usuario principal. A continuación, siga las indicaciones que aparezcan en su smartphone.", fi_FI="Älypuhelin ei ole käyttöönottotilassa. Käynnistä käyttöönottotila myAudi-sovelluksen kohdassa Digitaalinen avain. Voit käynnistää käyttöönoton myös linkistä, joka on lähetetty pääkäyttäjälle. Noudata sitten ohjeita älypuhelimesi näytöllä.", fr_FR="Votre smartphone n'est pas en mode de configuration. Veuillez lancer le mode de configuration dans l'application myAudi sous «Clé numérique». Vous pouvez également lancer la configuration via le lien envoyé à l'utilisateur principal. Suivez ensuite les instructions sur votre smartphone.", hr_HR="Vaš smartphone nije u modusu za uređivanje. Pokrenite modus za uređivanje u myAudi aplikaciji pod \"Digitalni ključ\". Alternativno uređivanje možete pokrenuti preko linka koji je poslan glavnom korisniku. Nakon toga slijedite upute na svom smartphoneu.", hu_HU="Az okostelefonod nincs beállítási módban. Indítsd el a beállítási módot a myAudi alkalmazásban a „Digitális kulcs” alatt. Alternatív lehetőségként a főfelhasználónak küldött linken keresztül is elindíthatod a beállítást. Ezután kövesd az okostelefonodon megjelenő utasításokat.", it_IT="Lo smartphone non è in modalità configurazione. Avviare la modalità configurazione nell'app myAudi alla voce \"Chiave digitale\". In alternativa, è possibile avviare la configurazione tramite il link inviato all'utente principale. Seguire quindi le indicazioni sullo smartphone.", nl_NL="Je smartphone staat niet in de installatiemodus. Start de installatiemodus in de myAudi-app onder \"Digitale sleutel\". Je kunt de installatie ook starten via de link die naar de hoofdgebruiker is verzonden. Volg daarna de instructies op je smartphone.", no_NO="Smarttelefonen er ikke i oppsettsmodus. Start oppsettsmodus under «Digital nøkkel» i myAudi-appen. Du kan også starte oppsettet ved hjelp av lenken som ble sendt til hovedbrukeren. Følg deretter instruksjonene på smarttelefonen.", pl_PL="Twój smartfon nie jest w trybie konfiguracji. Uruchom tryb konfiguracji w aplikacji myAudi w sekcji „Klucz cyfrowy”. Alternatywnie możesz rozpocząć konfigurację za pomocą linku wysłanego do głównego użytkownika. Następnie postępuj zgodnie z instrukcjami na smartfonie.", pt_PT="O teu smartphone não está no modo de configuração. Por favor, inicia o modo de configuração na myAudi app em \"Chave digital\". Em alternativa podes iniciar a configuração através do link que é enviado ao utilizador principal. Em seguida segue as instruções no teu smartphone.", ro_RO="Smartphone-ul dumneavoastră se află în modul de configurare. Porniţi modul de configurare în aplicaţia myAudi la \"Cheie digitală\". Alternativ puteţi iniţia configurarea prin linkul care a fost transmis utilizatorului principal. Urmaţi apoi instrucţiunile de pe smartphone.", ru_RU="Ваш смартфон не находится в режиме настройки. Пожалуйста, запустите режим настройки в приложении myAudi в разделе «Цифровой ключ». Кроме того, вы можете запустить настройку по ссылке, отправленной основному пользователю. Затем следуйте инструкциям на смартфоне.", sk_SK="Váš smartfón nie je v režime nastavenia. Prosím, spustite režim nastavenia v aplikácii myAudi v časti „Digitálny kľúč“. Prípadne môžete spustiť nastavenie prostredníctvom linku, ktorý bol zaslaný hlavnému používateľovi. Potom postupujte podľa pokynov v smartfóne.", sl_SI="Vaš pametni telefon ni v načinu za nastavitev. Zaženite način za nastavitev v meniju \"Digitalni ključ\" v aplikaciji myAudi. Nastavitev lahko zaženete tudi preko povezave, ki je bila poslana glavnemu uporabniku. Nato sledite navodilom na pametnem telefonu.", sr_RS="Vaš pametni telefon se ne nalazi u režimu uređivanja. Pokrenite režim uređivanja u aplikaciji myAudi pod opcijom „Digitalni ključ“.Alternativno uređivanje možete da pokrenete preko linka koji je dostavljen glavnom korisniku. Nakon toga sledite smernice na vašem pametnom telefonu.", sv_SE="Din smartphone är inte i inställningsläge. Aktivera inställningsläget i myAudi-appen under ”Digital nyckel”. Du kan även starta inställningen via länken som skickats till huvudanvändaren. Följ sedan anvisningarna på din smartphone.", tr_TR="Akıllı telefonun kurulum modunda değil. Lütfen myAudi uygulamasında “Dijital Anahtar” altında kurulum modunu başlat. Alternatif olarak, ana kullanıcıya gönderilen bağlantıyı kullanarak kurulumu başlatabilirsin. Ardından akıllı telefonundaki talimatları izley.", uk_UA="Ваш смартфон не перебуває в режимі налаштування. Будь ласка, запустіть режим налаштування в програмі myAudi в розділі «Цифровий ключ». Крім того, ви можете розпочати налаштування за посиланням, надісланим основному користувачеві. Потім дотримуйтесь інструкцій на вашому смартфоні.")
screen_content__mdk_no_password_title = TextObject(bs_BA="Neuspješno uređivanje digitalnog ključa", cs_CZ="Nepodařilo se nastavit digitální klíč", da_DK="Konfigurering af digital nøgle mislykkedes.", de_DE="Einrichten des digitalen Schlüssels fehlgeschlagen", el_GR="Η ρύθμιση του ψηφιακού κλειδιού απέτυχε", en_GB="Setup of digital key failed", es_ES="Error al configurar la llave digital", fi_FI="Digitaalisen avaimen muodostaminen epäonnistui", fr_FR="Échec de la configuration de la clé numérique", hr_HR="Uređivanje digitalnog ključa nije uspjelo", hu_HU="A digitális kulcs beállítása sikertelen", it_IT="Configurazione della chiave digitale non riuscita", nl_NL="Instellen van de digitale sleutel is mislukt", no_NO="Oppsett av den digitale nøkkelen mislyktes", pl_PL="Konfigurowanie klucza cyfrowego nie powiodło się", pt_PT="Configuração da chave digital falhou", ro_RO="Configurarea cheii digitale a eşuat", ru_RU="Не удалось настроить цифровой ключ", sk_SK="Nastavenie digitálneho kľúča sa nepodarilo", sl_SI="Nastavitev digitalnega ključa ni uspela", sr_RS="Neuspešno uređivanje digitalnog ključa", sv_SE="Inställningen av den digitala nyckeln misslyckades", tr_TR="Dijital anahtarın kurulumu başarısız oldu", uk_UA="Не вдалося налаштувати цифровий ключ")
screen_content__mdk_password_incorrect_blocked_description = TextObject(bs_BA="Lozinka za aktiviranje je nažalost blokirana. Ponovo pristupi lozinki za aktiviranje i ponovi postupak. Uvjeri se da imaš\naktivnu internet vezu.", cs_CZ="Heslo je bohužel zablokované. Heslo prosím vyvolejte znovu a postup zopakujte. zkontrolujte prosím, že máte aktivní\npřipojení k internetu.", da_DK="Konfigureringspasswordet er desværre spærret. Kald konfigureringspasswordet frem igen, og gentag processen.\nKontroller i den forbindelse, at du har en aktiv internetforbindelse.", de_DE="Das Einrichtungspasswort ist leider gesperrt. Bitte rufe das Einrichtungspasswort erneut ab und wiederhole den\nVorgang. Bitte stelle dazu sicher, dass du eine aktive Internetverbindung hast.", el_GR="Ο κωδικός πρόσβασης ρύθμισης έχει φραγεί. Καλέστε ξανά τον κωδικό πρόσβασης ρύθμισης και επαναλάβετε τη\nδιαδικασία. Για τον σκοπό αυτό βεβαιωθείτε ότι διαθέτετε ενεργή σύνδεση με το διαδίκτυο.", en_GB="The setup password is locked. Please call up the setup password again and repeat the process. To do so, please ensure\nthat you have an active Internet connection.", es_ES="La contraseña generada durante la configuración está bloqueada. Recupere la contraseña y repita el proceso. Asegúrese\nde tener conexión a Internet.", fi_FI="Käyttöönottosalasana on valitettavasti lukittu. Hae salasana uudelleen ja toista menettely. Varmista ennen sitä, että\nsinulla on aktiivinen internet-yhteys.", fr_FR="Le mot de passe de configuration est malheureusement bloqué. Veuillez faire une nouvelle demande de mot de passe de\nconfiguration et répétez la procédure. Veuillez vous assurer à cet effet que vous disposez d'une connexion Internet\nactive.", hr_HR="Lozinka za uređivanje na žalost je blokirana. Ponovno pozovite lozinku za uređivanje i ponovite postupak. U tu svrhu\nosigurajte aktivnu vezu s internetom.", hu_HU="A beállítási jelszó sajnos le van tiltva. Kérjük, újra kérd le a beállítási jelszót, és ismételd meg a folyamatot. Ehhez\ngyőződj meg róla, hogy rendelkezel aktív internetkapcsolattal.", it_IT="Purtroppo la password di configurazione è bloccata. Richiamare nuovamente la password di configurazione e ripetere\nl'operazione. Accertarsi di avere un collegamento internet attivo.", nl_NL="Sorry, het instellingswachtwoord is vergrendeld. Vraag het instellingswachtwoord opnieuw op en herhaal de bewerking.\nZorg ervoor dat je een actieve internetverbinding hebt.", no_NO="Oppsettspassordet er sperret. Hent oppsettspassordet igjen, og gjenta prosessen. Pass på at du har\ninternettforbindelse.", pl_PL="Hasło konfiguracyjne jest niestety zablokowane. Proszę ponownie wywołać hasło konfiguracyjne i powtórzyć procedurę.\nW tym celu proszę się upewnić, że masz połączenie z Internetem.", pt_PT="Infelizmente a palavra-passe da criação está bloqueada. Por favor, recupera a palavra-passe de criação e repita o\nprocedimento. Por favor, certifica-te primeiro que possuis uma ligação à Internet ativa.", ro_RO="Din păcate, parola de configurare este blocată. Reapelaţi parola de configurare şi reluaţi procedura. Asiguraţi-vă că\ndispuneţi de o conexiune activă la Internet.", ru_RU="К сожалению, пароль настройки заблокирован. Запросите пароль настройки еще раз и повторите процесс.\nУбедитесь в наличии активного интернет-соединения.", sk_SK="Žiaľ, heslo pre nastavenie je zablokované. Prosím, znova získajte heslo nastavenia a proces zopakujte. Uistite sa, že máte\naktívne internetové pripojenie.", sl_SI="Geslo za nastavitev je žal blokirano. Znova prikličite geslo za nastavitev in ponovite postopek. Poleg tega preverite, da\nimate aktivno internetno povezavo.", sr_RS="Lozinka za aktiviranje je nažalost blokirana. Ponovo pristupite lozinki za aktiviranje i ponovite postupak. Uverite se da\nimate aktivnu internet vezu.", sv_SE="Lösenordet för inställning har tyvärr spärrats. Ange ett nytt lösenord för inställning och upprepa förloppet. Säkerställ\natt du har en aktiv internetanslyuning.", tr_TR="Ne yazık ki, kurulum şifresi kilitli. Lütfen kurulum parolasını yeniden al ve işlemi tekrarla. Lütfen bunun için aktif bir\ninternet bağlantısı olduğundan emin ol.", uk_UA="На жаль, пароль налаштування заблоковано. Запросіть пароль ще раз і повторіть процес. Переконайтеся в наявності\nактивного з’єднання з Інтернетом.")
screen_content__mdk_password_incorrect_blocked_title = TextObject(bs_BA="Neuspješno uređivanje digitalnog ključa", cs_CZ="Nepodařilo se nastavit digitální klíč", da_DK="Konfigurering af digital nøgle mislykkedes.", de_DE="Einrichten des digitalen Schlüssels fehlgeschlagen", el_GR="Η ρύθμιση του ψηφιακού κλειδιού απέτυχε", en_GB="Setup of digital key failed", es_ES="Error al configurar la llave digital", fi_FI="Digitaalisen avaimen muodostaminen epäonnistui", fr_FR="Échec de la configuration de la clé numérique", hr_HR="Uređivanje digitalnog ključa nije uspjelo", hu_HU="A digitális kulcs beállítása sikertelen", it_IT="Configurazione della chiave digitale non riuscita", nl_NL="Instellen van de digitale sleutel is mislukt", no_NO="Oppsett av den digitale nøkkelen mislyktes", pl_PL="Konfigurowanie klucza cyfrowego nie powiodło się", pt_PT="Configuração da chave digital falhou", ro_RO="Configurarea cheii digitale a eşuat", ru_RU="Не удалось настроить цифровой ключ", sk_SK="Nastavenie digitálneho kľúča sa nepodarilo", sl_SI="Nastavitev digitalnega ključa ni uspela", sr_RS="Neuspešno uređivanje digitalnog ključa", sv_SE="Inställningen av den digitala nyckeln misslyckades", tr_TR="Dijital anahtarın kurulumu başarısız oldu", uk_UA="Не вдалося налаштувати цифровий ключ")
screen_content__mdk_password_incorrect_description = TextObject(bs_BA="Lozinka za aktiviranje je nažalost neispravna i glavni uređaj nije mogao biti aktiviran. Ponovi postupak s ispravnom\nlozinkom za aktivaciju.  Preostalo pokušaja: %1", cs_CZ="Heslo bohužel není správné a hlavní zařízení nelze vytvořit. Zopakujte prosím pokus se správným heslem.  Počet\nzbývajících pokusů: %1", da_DK="Konfigureringspasswordet er desværre ikke korrekt, og det primære apparat kunne ikke konfigureres. Gentag processen\nmed det korrekte konfigureringspassword.  Resterende forsøg: %1", de_DE="Das Einrichtungspasswort ist leider nicht korrekt und das Hauptgerät konnte nicht eingerichtet werden. Bitte wiederhole\nden Vorgang mit dem korrekten Einrichtungspasswort.  Verbleibende Versuche: %1", el_GR="Ο κωδικός πρόσβασης ρύθμισης δεν είναι σωστός και δεν κατέστη εφικτή η ρύθμιση της βασικής συσκευής. Επαναλάβετε\nτη διαδικασία με τον σωστό κωδικό πρόσβασης ρύθμισης.  Υπολειπόμενες προσπάθειες: %1", en_GB="Unfortunately, the setup password is incorrect and the main device could not be set up. Please repeat the process with\nthe correct setup password.  Attempts remaining: %1", es_ES="La contraseña no es correcta y el dispositivo principal no se ha podido configurar. Repita el proceso con la contraseña\ncorrecta.  Intentos disponibles: %1", fi_FI="Käyttöönottosalasana on valitettavasti virheellinen eikä päälaitetta voitu ottaa käyttöön. Toista menettely oikealla\nkäyttöönottosalasanalla.  Yrityksiä jäljellä: %1", fr_FR="Le mot de passe de configuration est malheureusement incorrect et le périphérique principal n'a pas pu être configuré.\nVeuillez répéter la procédure avec le bon mot de passe de configuration.  Nombre d'essais restants: %1", hr_HR="Lozinka za uređivanje na žalost nije ispravna i glavni uređaj nije kreiran. Ponovite postupak s pravilnom lozinkom za\nuređivanje.  Preostali pokušaji: %1", hu_HU="A beállítási jelszó sajnos helytelen, és a főkészüléket nem lehetett beállítani. Kérjük, ismételd meg a folyamatot a\nmegfelelő beállítási jelszóval.  Fennmaradó próbálkozások: %1", it_IT="Purtroppo la password di configurazione non è corretta e non è stato possibile configurare il dispositivo principale.\nRipeta l'operazione con la password di configurazione corretta.  Tentativi rimanenti: %1", nl_NL="Het instellingswachtwoord is helaas niet correct en het hoofdapparaat kon niet worden ingesteld. Herhaal de bewerking\nmet het correcte instellingswachtwoord.  Resterende pogingen: %1", no_NO="Oppsettspassordet er feil, og hovedenheten ble ikke satt opp. Gjenta prosessen med korrekt oppsettspassord.  Du har %1\nforsøk igjen", pl_PL="Hasło konfiguracyjne jest niestety nieprawidłowe i nie można skonfigurować urządzenia głównego. Proszę powtórzyć\nprocedurę z prawidłowym hasłem konfiguracyjnym.  Pozostało prób: %1", pt_PT="Infelizmente a palavra-passe de criação está incorreta e o aparelho principal não pode ser criado. Por favor, repete o\nprocedimento com a palavra-passe correta.  Tentativas restantes: %1", ro_RO="Parola de configurare este incorectă şi nu s-a putut configura dispozitivul principal. Repetaţi procedura cu parola de\nconfigurare corectă.  Încercări rămase: %1", ru_RU="К сожалению, пароль настройки неправильный, и основное устройство не может быть настроено. Повторите\nпроцесс с правильным паролем настройки.  Осталось попыток: %1", sk_SK="Žiaľ heslo nastavenia je nesprávne a hlavné zariadenie sa nepodarilo nastaviť. Prosím, skúste to znova so správnym\nheslom nastavenia.  Zostávajúce pokusy: %1", sl_SI="Geslo za nastavitev žal ni pravilno in glavne naprave ni bilo mogoče nastaviti. Postopek ponovite s pravilnim geslom za\nnastavitev.  Preostali poskusi: %1", sr_RS="Lozinka za aktiviranje je nažalost neispravna i glavni uređaj nije mogao biti aktiviran. Ponovite postupak s ispravnom\nlozinkom za aktivaciju.  Preostalo pokušaja: %1", sv_SE="Lösenordet för inställning är tyvärr inte korrekt och huvudenheten kunde inte ställas in. Upprepa förloppet med korrekt\nlösenord för inställning.  Återstående försök: %1", tr_TR="Maalesef kurulum şifresi doğru değil ve ana cihaz kurulumu yapılamadı. Lütfen işlemi doğru kurulum şifresi ile tekrarla. \nKalan deneme sayısı: %1", uk_UA="На жаль, пароль налаштування неправильний, і основний пристрій не може бути налаштований. Повторіть процес\nіз правильним паролем налаштування.  Залишилось спроб: %1")
screen_content__mdk_password_incorrect_title = TextObject(bs_BA="Neuspješno uređivanje digitalnog ključa", cs_CZ="Nepodařilo se nastavit digitální klíč", da_DK="Konfigurering af digital nøgle mislykkedes.", de_DE="Einrichten des digitalen Schlüssels fehlgeschlagen", el_GR="Η ρύθμιση του ψηφιακού κλειδιού απέτυχε", en_GB="Setup of digital key failed", es_ES="Error al configurar la llave digital", fi_FI="Digitaalisen avaimen muodostaminen epäonnistui", fr_FR="Échec de la configuration de la clé numérique", hr_HR="Uređivanje digitalnog ključa nije uspjelo", hu_HU="A digitális kulcs beállítása sikertelen", it_IT="Configurazione della chiave digitale non riuscita", nl_NL="Instellen van de digitale sleutel is mislukt", no_NO="Oppsett av den digitale nøkkelen mislyktes", pl_PL="Konfigurowanie klucza cyfrowego nie powiodło się", pt_PT="Configuração da chave digital falhou", ro_RO="Configurarea cheii digitale a eşuat", ru_RU="Не удалось настроить цифровой ключ", sk_SK="Nastavenie digitálneho kľúča sa nepodarilo", sl_SI="Nastavitev digitalnega ključa ni uspela", sr_RS="Neuspešno uređivanje digitalnog ključa", sv_SE="Inställningen av den digitala nyckeln misslyckades", tr_TR="Dijital anahtarın kurulumu başarısız oldu", uk_UA="Не вдалося налаштувати цифровий ключ")
screen_content__privacy_description_clu43 = TextObject(bs_BA="Za bolji doživljaj vozila, možete aktivirati mobilne podatke za korištenje online usluga i time dati saglasnost za preuzimanje\naktualizacija softvera. Upravljanje izborom odnosno opoziv izbora možete u svakom trenutku izvršiti u postavkama za\nzaštitu podataka. Pojedinosti o online uslugama možete pročitati u napomenama za zaštitu podataka.", cs_CZ="Pro zvýšení zážitků s vozidlem můžete aktivovat mobilní data pro využívání online služeb, čímž povolíte download\naktualizačního softwaru. Svou volbu můžete kdykoli spravovat, resp. odvolat v nastavení ochrany dat. Podrobnosti k online\nslužbám se dozvíte v pokynech k ochraně dat.", da_DK="For en bedre biloplevelse kan du aktivere mobildata til anvendelse af onlinetjenester og dermed give samtykke til\ndownloading af softwareopdateringer. Du kan til enhver tid administrere eller tilbagekalde dette i\ndatabeskyttelsesindstillingerne. Du kan læse detaljerede informationer vedr. onlinetjenesterne i\ndatabeskytelsesinformationerne.", de_DE="Für ein besseres Fahrzeugerlebnis kannst du mobile Daten zur Nutzung von Online-Diensten aktivieren und damit in den\nDownload von Software-Updates einwilligen. Du kannst dies jederzeit in den Datenschutzeinstellungen verwalten bzw.\nwiderrufen. Details zu den Online-Diensten kannst du in den Datenschutzhinweisen nachlesen.", el_GR="Για μια καλύτερη εμπειρία με το όχημα, μπορείτε να ενεργοποιήσετε τα δεδομένα κινητής τηλεφωνίας για τη χρήση online\nυπηρεσιών, συναινώντας με τον τρόπο αυτό στη λήψη (download) αναβαθμίσεων λογισμικού. Αυτό μπορείτε ανά πάσα στιγμή\nνα το διαχειριστείτε ή να το ανακαλέσετε στις ρυθμίσεις προστασίας δεδομένων. Λεπτομέρειες σχετικά με τις online υπηρεσίες\nμπορείτε να βρείτε στις υποδείξεις προστασίας δεδομένων προσωπικού χαρακτήρα.", en_GB="For a better in-car experience, you can activate mobile data to use online services and thereby consent to the software\nupdate downloads. You can manage this and revoke your consent at any time in the privacy settings. Detailed information\non online services can be found in the data protection notes.", es_ES="Si desea aumentar la experiencia de la conducción, puede activar los datos móviles para utilizar los servicios online y, así,\npermitir la descarga de actualizaciones de software. Esto se puede gestionar en todo momento en los ajustes de privacidad.\nEncontrará todos los detalles sobre los servicios online en el aviso de privacidad.", fi_FI="Paremman ajokokemuksen saavuttamiseksi voit aktivoida mobiilidatan käyttääksesi online-palveluja ja siten hyväksyä\nohjelmistopäivitysten lataamisen. Voit milloin tahansa hallinnoida toimintoa tietosuoja-asetuksista tai perua sen.\nTarkempia tietoja online-palveluista saat tietosuojaohjeista.", fr_FR="Pour une meilleure expérience du véhicule, vous pouvez activer les données mobiles pour utiliser les services en ligne et\nainsi consentir au téléchargement des mises à jour logicielles. Vous pouvez gérer ou révoquer cela à tout moment dans les\nréglages de la confidentialité. Vous trouverez des détails sur les services en ligne dans les informations relatives à la\nprotection des données.", hr_HR="Kako biste obogatili svoj doživljaj vožnje, možete aktivirati mobilne podatke za korištenje online usluga i tako odobriti\ndownload softverskih ažuriranja. Time možete upravljati odnosno možete to u svakom trenutku opozvati u postavkama\nzaštite podataka. Detaljne informacije o online uslugama možete pronaći u napomenama o zaštiti podataka.", hu_HU="Még élménytelibbé teheted a jármű használatát azzal, hogy aktiválod a mobil adatokat az online szolgáltatások\nhasználatához, és ezzel hozzájárulsz a szoftverfrissítések letöltéséhez. Ezt az adatvédelmi beállításokban bármikor\nkezelheted, ill. visszavonhatod. Az online szolgáltatásokkal kapcsolatos részleteket az adatvédelmi irányelvek tartalmazzák.", it_IT="Per migliorare l'esperienza a bordo, è possibile attivare i dati mobili per utilizzare i servizi online e acconsentire così al\ndownload degli update software. È possibile gestire o revocare in qualunque momento questa funzionalità nelle\nimpostazioni per la protezione dati. Per dettagli sui servizi online consultare le avvertenze sulla protezione dati.", nl_NL="Voor een betere voertuigervaring kun je mobiele gegevens voor het gebruik van onlinediensten activeren en daarmee\ntoestemming geven voor het downloaden van software-updates. Je kunt dit altijd in je privacy-instellingen beheren en je\ntoestemming intrekken. Details over onlinediensten kun je nalezen in de richtlijnen voor gegevensbescherming.", no_NO="Du kan aktivere mobildata for å bruke online-tjenestene og få en enda bedre kjøreopplevelse. Da samtykker du også i\nnedlasting av programvareoppdateringer. Du kan når som helst administrere valgene dine og trekke tilbake samtykket i\npersonverninnstillingene. Du kan lese mer om online-tjenestene i personverninformasjonen.", pl_PL="Aby uzyskać lepsze wrażenia z użytkowania pojazdu, możesz włączyć dane mobilne, aby korzystać z usług online i wyrazić\nzgodę na pobieranie aktualizacji oprogramowania. Możesz mią zarządzać lub ją wycofać w każdej chwili w ustawieniach\nprywatności. Szczegóły dotyczące usług online można przeczytać w polityce prywatności.", pt_PT="Para uma melhor experiência auomóvel podes ativar os dados móveis para utilização de serviços online e permitir o\ndownload de atualizações de software. Podes gerir ou cancelar isto em qualquer altura nos ajustes da proteção de dados.\nPodes consultar os detalhes sobre os serviços online nas indicações da proteção de dados.", ro_RO="Pentru îmbunătăţirea experienţei cu autovehiculul, puteţi activa datele mobile pentru utilizarea serviciilor online, acceptând\nastfel descărcarea actualizărilor software. Puteţi administra respectiv revoca acest lucru în orice moment, în setările de\nprotecţia datelor. Detalii referitoare la serviciile online puteţi afla din indicaţiile privind protecţia datelor.", ru_RU="Для более удобной эксплуатации автомобиля вы можете включить мобильные данные для использования\nонлайн-сервисов и дать согласие на загрузку обновлений программного обеспечения. Вы можете в любой момент\nизменить или отменить это в настройках защиты данных. Подробную информацию об онлайн-сервисах вы можете\nнайти в примечаниях по защите данных.", sk_SK="Aby ste vylepšili svoj zážitok z jazdy vo vozidle, môžete aktivovať mobilné dáta na používanie online služieb a tým súhlasiť so\nsťahovaním aktualizácií softvéru. To môžete kedykoľvek spravovať alebo odvolať v nastaveniach ochrany údajov. Podrobnosti\no online službách si môžete prečítať v upozorneniach o ochrane údajov.", sl_SI="Za boljše doživetje vožnje lahko mobilne podatke aktivirate za uporabo spletnih storitev in s tem soglašate s prenosom\nposodobitev programske opreme. Soglasje lahko kadar koli upravljate oz. prekličete v nastavitvah zasebnosti. Podrobnosti o\nspletnih storitvah lahko preberete v obvestilih o varstvu podatkov.", sr_RS="Za bolji doživljaj vozila, možete da aktivirate mobilne podatke kako biste koristili onlajn usluge i time dali saglasnost za\npreuzimanje ažuriranja softvera. Upravljanje izborom odnosno opoziv izbora možete u svakom trenutku da izvršite u\npodešavanjima za zaštitu podataka. Detaljne informacije o onlajn uslugama možete da pročitate u napomenama o zaštiti\npodataka.", sv_SE="För en bättre körupplevelse kan du aktivera mobildata för användning av onlinetjänster och därmed ge samtycke till\nnedladdning av programvaruuppdateringar. Du kan när som helst hantera eller dra tillbaka ditt samtycke i\nintegritetsinställningarna. Information om onlinetjänsterna hittar du i integritetsinformationen.", tr_TR="Daha iyi bir araç deneyimi için, çevrimiçi hizmetleri kullanmak üzere mobil verileri etkinleştirbilir ve böylece yazılım\ngüncellemelerinin indirilmesine izin verebilirsin. Bunu istediğin zaman veri koruma ayarlarında yönetebilir veya iptal\nedebilirsin. Çevrimiçi hizmetler hakkındaki ayrıntıları veri koruma bilgilerinde okuyabilirsin.", uk_UA="Для зручнішої експлуатації автомобіля ви можете увімкнути мобільні дані для використання онлайн-служб і дати згоду\nна завантаження оновлень програмного забезпечення. Ви можете в будь-який момент змінити або скасувати це в\nналаштуваннях захисту даних. Детальну інформацію про онлайн-служби ви можете знайти в примітках щодо захисту\nданих.")
screen_content__privacy_description_deactivated = TextObject(bs_BA="Da biste povećali doživljaj vozila, možete uključiti online usluge kako biste ih koristili. Na taj način deaktivirate režim zaštite\npodataka. Detaljne informacije o online uslugama možete pročitati u napomenama za zaštitu podataka. Svojim odabirom\nmožete uvijek upravljati u postavkama za zaštitu podataka.", cs_CZ="Pro zvýšení svého požitku z jízdy můžete zapnout a používat služby online. Tím deaktivujete režim ochrany dat. Detaily ke\nslužbám online najdete v pokynech k ochraně dat. Svou volbu můžete kdykoli spravovat v nastaveních ochrany dat.", da_DK="For at forbedre din køreoplevelse kan du aktivere onlinetjenester med henblik på at anvende dem. Derved deaktiverer du\ndatabeskyttelsesfunktionen. Du kan læse nærmere om onlinetjenesterne i databeskyttelsesinformationerne. Du kan til\nenhver tid administrere dit valg i databeskyttelsesindstillingerne.", de_DE="Um dein Fahrzeugerlebnis zu erhöhen, kannst du Online-Dienste einschalten, um diese zu nutzen. Dadurch deaktivierst du\nden Datenschutzmodus. Details zu den Online-Diensten kannst du in den Datenschutzhinweisen nachlesen. Du kannst deine\nAuswahl jederzeit in den Datenschutzeinstellungen verwalten.", el_GR="Για να βελτιώσετε την εμπειρία που ζείτε με το όχημά σας, μπορείτε να ενεργοποιήσετε τις online υπηρεσίες, ώστε να τις\nχρησιμοποιήσετε. Από αυτό θα απενεργοποιηθεί η λειτουργία προστασίας προσωπικών δεδομένων. Για λεπτομέρειες σχετικά\nμε τις online υπηρεσίες, ανατρέξτε στις υποδείξεις προστασίας δεδομένων προσωπικού χαρακτήρα. Μπορείτε να\nδιαχειριστείτε τις επιλογές σας ανά πάσα στιγμή στις ρυθμίσεις προστασίας προσωπικών δεδομένων.", en_GB="For more in-car experiences, you can switch online services on to use them. Doing this deactivates privacy mode. For details\non the online services, refer to the data protection notes. You can manage your selection at any time in the privacy settings.", es_ES="Conecte los servicios online para sacarles provecho y aumentar la experiencia de la conducción. Al hacerlo se desactiva el\nmodo de privacidad. Encontrará los detalles sobre los servicios online en el aviso de privacidad. Las opciones seleccionadas\nse pueden cambiar en todo momento en los ajustes de privacidad.", fi_FI="Voit parantaa autoilukokemustasi käynnistämällä ja käyttämällä online-palveluja. Samalla tietosuojatila deaktivoituu.\nTarkemmat tiedot online-palveluista voit lukea tietosuojaohjeista. Voit milloin tahansa hallinnoida valintojasi\ntietosuoja-asetustesi kautta.", fr_FR="Pour une meilleure expérience avec votre véhicule, vous pouvez activer des services en ligne afin de les utiliser. Cela\ndésactivera alors le mode de confidentialité. Vous trouverez des détails sur les services en ligne dans les informations\nrelatives à la protection des données. Vous pouvez gérer vos choix à tout moment dans les réglages de la confidentialité.", hr_HR="Kako biste obogatili svoj doživljaj vozila, možete uključiti online usluge kako biste ih koristili. Na taj način aktivirate modus\nzaštite podataka. Detaljne informacije o online uslugama možete pronaći u napomenama o zaštiti podataka. Svojim\nodabirom možete u svakom trenutku upravljati preko postavki zaštite podataka.", hu_HU="Még élménytelibbé teheted a jármű használatát azzal, hogy bekapcsolod az online szolgáltatásokat a használatukhoz. Ezzel\nkikapcsolod az adatvédelmi módot. Az online szolgáltatásokkal kapcsolatos részleteket az adatvédelmi irányelvek\ntartalmazzák. A választott opciót bármikor kezelheted az adatvédelmi beállításokban.", it_IT="Per migliorare l'esperienza a bordo della vettura, può attivare i servizi online per utilizzarli. In questo modo si disattiva la\nmodalità protezione dati. Per dettagli sui servizi online consulti le avvertenze sulla protezione dati. Può gestire le Sue scelte\nin qualunque momento nelle impostazioni per la protezione dati.", nl_NL="Om je voertuigervaring te verbeteren, kun je onlinediensten inschakelen om te gebruiken. Hierdoor wordt de privacymodus\nuitgeschakeld. Voor meer informatie over de onlinediensten, zie de privacyrichtlijnen. Je kunt je keuzes op elk moment\nherzien in de privacy-instellingen.", no_NO="Du kan slå på og bruke online-tjenestene for å få en enda bedre kjøreopplevelse. Da deaktiveres personvernmodusen. Du kan\nlese mer om online-tjenestene i personverninformasjonen. Du kan når som helst tilpasse valgene dine i\npersonverninnstillingene.", pl_PL="Aby poprawić wrażenia związane z korzystaniem z pojazdu, możesz włączyć usługi online i z nich korzystać. Spowoduje to\nwyłączenie trybu prywatności. Szczegółowe informacje na temat usług online można znaleźć w polityce prywatności. Swoim\nwyborem możesz w każdej chwili zarządzać w ustawieniach prywatności.", pt_PT="Para aumentar a tua experiência com o veículo podes ligar os serviços online para os poderes utilizar. Com isto, desativas o\nmodo de proteção de dados. Podes consultar os detalhes sobre os serviços online na política de proteção de dados. Em\nqualquer altura podes gerir a tua opção nos ajustes da proteção de dados.", ro_RO="Pentru a îmbunătăţi experienţa dumneavoastră cu autovehiculul, puteţi activa servicii online, pentru a le utiliza. Astfel\ndezactivaţi modul de protecţia datelor. Detalii referitoare la serviciile online puteţi afla din indicaţiile privind protecţia\ndatelor. Puteţi administra selecţia în orice moment, în setările de protecţia datelor.", ru_RU="Чтобы повысить комфорт при эксплуатации автомобиля, Вы можете включить онлайн-сервисы, чтобы использовать их.\nЭтим Вы отключите режим защиты данных. Подробную информацию об онлайн-сервисах можно посмотреть в\nпримечаниях по защите данных. Свой выбор можно изменить в любое время в настройках защиты данных.", sk_SK="Ak chcete zvýšiť zážitok z jazdy, môžete zapnúť online služby pre ich používanie. Tým deaktivujete režim ochrany údajov.\nDetaily o online službách si môžete prečítať v pokynoch o ochrane údajov. Váš výber môžete kedykoľvek spravovať v\nnastaveniach ochrany údajov.", sl_SI="Za izboljšanje vašega doživetja vožnje lahko spletne storitve vključite za uporabo. S tem deaktivirate zasebni način.\nPodrobnosti o spletnih storitvah lahko preberete v obvestilih o varstvu podatkov. Svojo izbiro lahko kadar koli upravljate v\nnastavitvah zasebnosti.", sr_RS="Da biste povećali doživljaj vozila, možete da uključite online usluge kako biste ih koristili. Na taj način deaktivirate režim za\nzaštitu podataka. Detaljne informacije o online uslugama možete da pročitate u napomenama za zaštitu podataka. Svojim\nizborom možete uvek da upravljate u podešavanjima za zaštitu podataka.", sv_SE="För att förbättra din fordonsupplevelse kan du aktivera onlinetjänster för att använda dem. Detta inaktiverar\nsekretessläget. Du kan läsa mer om onlinetjänsterna i integritetsinformationen. Du kan hantera ditt val när som helst i\nintegritetsinställningarna.", tr_TR="Araç deneyimini artırmak için, bunları kullanmak üzere çevrimiçi hizmetleri açabilirsin. Böylece gizlilik modunu devre dışı\nbırakırsın. Çevrimiçi hizmetler hakkındaki ayrıntıları veri koruma bilgilerinde okuyabilirsin. Seçimini istediğin zaman gizlilik\nayarlarında yönetebilirsin.", uk_UA="Щоб підвищити комфорт під час експлуатації автомобіля, ви можете увімкнути онлайнові служби, щоб\nвикористовувати їх. Цим ви вимкнете режим захисту даних. Детальну інформацію про онлайнові служби можна\nпереглянути у вказівках із захисту даних. Свій вибір можна змінити у будь-який час у настройках захисту даних.")
screen_content__privacy_description_meb = TextObject(de_DE="Um dein Fahrzeugerlebnis zu erhöhen, kannst du Online-Dienste einschalten, um diese zu nutzen. Dadurch deaktivierst du\nden Datenschutzmodus. Details zu den Online-Diensten kannst du in den Datenschutzhinweisen nachlesen. Du kannst deine\nAuswahl jederzeit in den Datenschutzeinstellungen verwalten.  Hinweis: Das Fahrzeug wird automatisch online gehen, um\nnach Software-Updates zu suchen und Systemstabilität zu gewährleisten, auch wenn die mobilen Daten deaktiviert sind.")
screen_content__privacy_description_time_limit = TextObject(bs_BA="Za bolji doživljaj vozila, možete aktivirati mobilne podatke za korištenje online usluga i time dati saglasnost za preuzimanje\naktualizacija softvera. Upravljanje izborom odnosno opoziv izbora možete u svakom trenutku izvršiti u postavkama za\nzaštitu podataka. Pojedinosti o online uslugama možete pročitati u napomenama za zaštitu podataka.", cs_CZ="Pro zvýšení zážitků s vozidlem můžete aktivovat mobilní data pro využívání online služeb, čímž povolíte download\naktualizačního softwaru. Svou volbu můžete kdykoli spravovat, resp. odvolat v nastavení ochrany dat. Podrobnosti k online\nslužbám se dozvíte v pokynech k ochraně dat.", da_DK="For en bedre biloplevelse kan du aktivere mobildata til anvendelse af onlinetjenester og dermed give samtykke til\ndownloading af softwareopdateringer. Du kan til enhver tid administrere eller tilbagekalde dette i\ndatabeskyttelsesindstillingerne. Du kan læse detaljerede informationer vedr. onlinetjenesterne i\ndatabeskytelsesinformationerne.", de_DE="Für ein besseres Fahrzeugerlebnis kannst du mobile Daten zur Nutzung von Online-Diensten aktivieren und damit in den\nDownload von Software-Updates einwilligen. Du kannst dies jederzeit in den Datenschutzeinstellungen verwalten bzw.\nwiderrufen. Details zu den Online-Diensten kannst du in den Datenschutzhinweisen nachlesen.", el_GR="Για μια καλύτερη εμπειρία με το όχημα, μπορείτε να ενεργοποιήσετε τα δεδομένα κινητής τηλεφωνίας για τη χρήση online\nυπηρεσιών, συναινώντας με τον τρόπο αυτό στη λήψη (download) αναβαθμίσεων λογισμικού. Αυτό μπορείτε ανά πάσα στιγμή\nνα το διαχειριστείτε ή να το ανακαλέσετε στις ρυθμίσεις προστασίας δεδομένων. Λεπτομέρειες σχετικά με τις online υπηρεσίες\nμπορείτε να βρείτε στις υποδείξεις προστασίας δεδομένων προσωπικού χαρακτήρα.", en_GB="For a better in-car experience, you can activate mobile data to use online services and thereby consent to the software\nupdate downloads. You can manage this and revoke your consent at any time in the privacy settings. Detailed information\non online services can be found in the data protection notes.", es_ES="Si desea aumentar la experiencia de la conducción, puede activar los datos móviles para utilizar los servicios online y, así,\npermitir la descarga de actualizaciones de software. Esto se puede gestionar en todo momento en los ajustes de privacidad.\nEncontrará todos los detalles sobre los servicios online en el aviso de privacidad.", fi_FI="Paremman ajokokemuksen saavuttamiseksi voit aktivoida mobiilidatan käyttääksesi online-palveluja ja siten hyväksyä\nohjelmistopäivitysten lataamisen. Voit milloin tahansa hallinnoida toimintoa tietosuoja-asetuksista tai perua sen.\nTarkempia tietoja online-palveluista saat tietosuojaohjeista.", fr_FR="Pour une meilleure expérience du véhicule, vous pouvez activer les données mobiles pour utiliser les services en ligne et\nainsi consentir au téléchargement des mises à jour logicielles. Vous pouvez gérer ou révoquer cela à tout moment dans les\nréglages de la confidentialité. Vous trouverez des détails sur les services en ligne dans les informations relatives à la\nprotection des données.", hr_HR="Kako biste obogatili svoj doživljaj vožnje, možete aktivirati mobilne podatke za korištenje online usluga i tako odobriti\ndownload softverskih ažuriranja. Time možete upravljati odnosno možete to u svakom trenutku opozvati u postavkama\nzaštite podataka. Detaljne informacije o online uslugama možete pronaći u napomenama o zaštiti podataka.", hu_HU="Még élménytelibbé teheted a jármű használatát azzal, hogy aktiválod a mobil adatokat az online szolgáltatások\nhasználatához, és ezzel hozzájárulsz a szoftverfrissítések letöltéséhez. Ezt az adatvédelmi beállításokban bármikor\nkezelheted, ill. visszavonhatod. Az online szolgáltatásokkal kapcsolatos részleteket az adatvédelmi irányelvek tartalmazzák.", it_IT="Per migliorare l'esperienza a bordo, è possibile attivare i dati mobili per utilizzare i servizi online e acconsentire così al\ndownload degli update software. È possibile gestire o revocare in qualunque momento questa funzionalità nelle\nimpostazioni per la protezione dati. Per dettagli sui servizi online consultare le avvertenze sulla protezione dati.", nl_NL="Voor een betere voertuigervaring kun je mobiele gegevens voor het gebruik van onlinediensten activeren en daarmee\ntoestemming geven voor het downloaden van software-updates. Je kunt dit altijd in je privacy-instellingen beheren en je\ntoestemming intrekken. Details over onlinediensten kun je nalezen in de richtlijnen voor gegevensbescherming.", no_NO="Du kan aktivere mobildata for å bruke online-tjenestene og få en enda bedre kjøreopplevelse. Da samtykker du også i\nnedlasting av programvareoppdateringer. Du kan når som helst administrere valgene dine og trekke tilbake samtykket i\npersonverninnstillingene. Du kan lese mer om online-tjenestene i personverninformasjonen.", pl_PL="Aby uzyskać lepsze wrażenia z użytkowania pojazdu, możesz włączyć dane mobilne, aby korzystać z usług online i wyrazić\nzgodę na pobieranie aktualizacji oprogramowania. Możesz mią zarządzać lub ją wycofać w każdej chwili w ustawieniach\nprywatności. Szczegóły dotyczące usług online można przeczytać w polityce prywatności.", pt_PT="Para uma melhor experiência auomóvel podes ativar os dados móveis para utilização de serviços online e permitir o\ndownload de atualizações de software. Podes gerir ou cancelar isto em qualquer altura nos ajustes da proteção de dados.\nPodes consultar os detalhes sobre os serviços online nas indicações da proteção de dados.", ro_RO="Pentru îmbunătăţirea experienţei cu autovehiculul, puteţi activa datele mobile pentru utilizarea serviciilor online, acceptând\nastfel descărcarea actualizărilor software. Puteţi administra respectiv revoca acest lucru în orice moment, în setările de\nprotecţia datelor. Detalii referitoare la serviciile online puteţi afla din indicaţiile privind protecţia datelor.", ru_RU="Для более удобной эксплуатации автомобиля вы можете включить мобильные данные для использования\nонлайн-сервисов и дать согласие на загрузку обновлений программного обеспечения. Вы можете в любой момент\nизменить или отменить это в настройках защиты данных. Подробную информацию об онлайн-сервисах вы можете\nнайти в примечаниях по защите данных.", sk_SK="Aby ste vylepšili svoj zážitok z jazdy vo vozidle, môžete aktivovať mobilné dáta na používanie online služieb a tým súhlasiť so\nsťahovaním aktualizácií softvéru. To môžete kedykoľvek spravovať alebo odvolať v nastaveniach ochrany údajov. Podrobnosti\no online službách si môžete prečítať v upozorneniach o ochrane údajov.", sl_SI="Za boljše doživetje vožnje lahko mobilne podatke aktivirate za uporabo spletnih storitev in s tem soglašate s prenosom\nposodobitev programske opreme. Soglasje lahko kadar koli upravljate oz. prekličete v nastavitvah zasebnosti. Podrobnosti o\nspletnih storitvah lahko preberete v obvestilih o varstvu podatkov.", sr_RS="Za bolji doživljaj vozila, možete da aktivirate mobilne podatke kako biste koristili onlajn usluge i time dali saglasnost za\npreuzimanje ažuriranja softvera. Upravljanje izborom odnosno opoziv izbora možete u svakom trenutku da izvršite u\npodešavanjima za zaštitu podataka. Detaljne informacije o onlajn uslugama možete da pročitate u napomenama o zaštiti\npodataka.", sv_SE="För en bättre körupplevelse kan du aktivera mobildata för användning av onlinetjänster och därmed ge samtycke till\nnedladdning av programvaruuppdateringar. Du kan när som helst hantera eller dra tillbaka ditt samtycke i\nintegritetsinställningarna. Information om onlinetjänsterna hittar du i integritetsinformationen.", tr_TR="Daha iyi bir araç deneyimi için, çevrimiçi hizmetleri kullanmak üzere mobil verileri etkinleştirbilir ve böylece yazılım\ngüncellemelerinin indirilmesine izin verebilirsin. Bunu istediğin zaman veri koruma ayarlarında yönetebilir veya iptal\nedebilirsin. Çevrimiçi hizmetler hakkındaki ayrıntıları veri koruma bilgilerinde okuyabilirsin.", uk_UA="Для зручнішої експлуатації автомобіля ви можете увімкнути мобільні дані для використання онлайн-служб і дати згоду\nна завантаження оновлень програмного забезпечення. Ви можете в будь-який момент змінити або скасувати це в\nналаштуваннях захисту даних. Детальну інформацію про онлайн-служби ви можете знайти в примітках щодо захисту\nданих.")
screen_content__privacy_sensitive_data_description = TextObject(bs_BA="Odlučite koje od sljedećih postavki želite aktivirati za usluge u svom vozilu. Imajte na umu da su infotainment sistemu\neventualno potrebna dodatna ovlaštenja za obradu i prenos određenih ličnih podataka. Online obrada podataka vrši se\nsamo kada su mobilni podaci aktivirani.", cs_CZ="Rozhodněte, která z následujících nastavení mají být aktivována pro služby ve vašem vozidle. Vezměte prosím na vědomí,\nže váš systém Infotainment může vyžadovat další oprávnění pro zpracování a přenos určitých osobních údajů. Zpracování\ndat online probíhá pouze v případě, že jsou aktivována mobilní data.", da_DK="Beslut dig for, hvilke af følgende indstillinger der skal aktiveres for tjenesterne i din bil. Vær opmærksom på, at dit\ninfotainmentsystem muligvis kan have brug for yderligere autorisationer til behandling og overførsel af visse\npersonrelaterede data. Onlinedatabehandling sker kun ved aktivering af mobildata.", de_DE="Bitte entscheide, welche der folgenden Einstellungen für die Dienste in deinem Fahrzeug aktiviert werden sollen. Beachte,\ndass dein Infotainmentsystem ggf. weitere Berechtigungen für die Verarbeitung und Übertragung von bestimmten\npersonenbezogenen Daten benötigt. Eine Online-Datenverarbeitung erfolgt nur bei Aktivierung der mobilen Daten.", el_GR="Αποφασίστε ποιες από τις παρακάτω ρυθμίσεις πρέπει να ενεργοποιηθούν για τις υπηρεσίες στο όχημά σας. Έχετε υπόψη\nότι το σύστημα Infotainment σας χρειάζεται ενδεχομένως περαιτέρω δικαιώματα για την επεξεργασία και μεταβίβαση\nορισμένων δεδομένων προσωπικού χαρακτήρα. Η online επεξεργασία λαμβάνει χώρα μόνο όταν είναι ενεργοποιημένα τα\nδεδομένα κινητής τηλεφωνίας.", en_GB="Please decide which of the following settings should be activated for services in your vehicle. Please note that your\ninfotainment system may require further authorisations for processing and and transmitting certain types of personal\ndata. Online data processing is only performed when mobile data is activated.", es_ES="Indique cuáles de los siguientes ajustes desea activar para los servicios en su vehículo. Tenga en cuenta que su servicio de\ninfotainment puede necesitar más permisos para procesar y transmitir determinados datos personales. Los datos online\nsolo se tratan con los datos móviles activados.", fi_FI="Voit valita, minkä seuraavista palvelua koskevista asetuksista haluat aktivoida. Ota huomioon, että\ninfotainment-järjestelmäsi saattaa tarvita lisää oikeuksia tiettyjen henkilötietojen käsittelyyn ja siirtämiseen.\nOnline-tietoja käsitellään vain, kun mobiilidata on aktivoitu.", fr_FR="Veuillez décider lesquels des réglages suivants doivent être activés pour les services dans votre véhicule. Veuillez tenir\ncompte du fait que votre système d'infodivertissement peut nécessiter des autorisations supplémentaires pour traiter et\ntransférer certaines données à caractère personnel. Le traitement des données en ligne n'a lieu que lorsque les données\nmobiles sont activées.", hr_HR="Odlučite se koje od sljedećih postavki za usluge u vašem vozilu želite aktivirati. Imajte na umu da vaš infotainment\neventualno treba dodatna odobrenja za obradu i prijenos određenih osobnih podataka. Obrada online podataka vrši se\nsamo uz aktiviranje mobilnih podataka.", hu_HU="Kérünk, dönts arról, hogy a következő beállítások közül melyeket szeretnéd aktiválni a járművedben elérhető\nszolgáltatásokhoz. Vedd figyelembe, hogy infotainment-rendszered számára esetleg további engedélyek lehetnek\nszükségesek bizonyos személyes adatok feldolgozásához és továbbításához. Az online adatfeldolgozás csak a\nmobiladatok aktiválása után történik meg.", it_IT="Decida quali delle seguenti impostazioni per i servizi a bordo della vettura debbano essere attivate. Tenga presente che il\nsistema di infotainment potrebbe richiedere ulteriori autorizzazioni per il trattamento e la trasmissione di determinati\ndati personali. L'elaborazione dei dati online avviene solo all'attivazione dei dati mobili.", nl_NL="Bepaal welke van de volgende instellingen voor de diensten in je voertuig dienen te worden geactiveerd. Houd er rekening\nmee dat voor je infotainmentsysteem eventueel andere autorisaties voor de verwerking en overdracht van bepaalde\npersoonsgerelateerde gegevens vereist zijn. Een online gegevensverwerking kan alleen plaatsvinden wanneer mobiele\ndata zijn geactiveerd.", no_NO="Velg hvilke av følgende innstillinger som skal aktiveres for tjenestene i bilen din. Merk: Det kan hende du må gi flere\ntillatelser for at infotainmentsystemet skal kunne behandle og overføre visse personopplysninger. Opplysningene kan\nbare behandles online hvis du aktiverer mobildata.", pl_PL="Proszę zdecydować, które z poniższych ustawień powinny zostać włączone dla usług w pojeździe. Należy pamiętać, że\nsystem Infotainment może wymagać dodatkowych uprawnień do przetwarzania i przesyłania niektórych danych\nosobowych. Przetwarzanie danych online odbywa się tylko wtedy, gdy dane mobilne są włączone.", pt_PT="Por favor, decide qual dos seguintes ajustes deve ser ativado para os serviços no teu veículo. Tem em consideração que o\nteu sistema Infotainment poderá necessitar de mais permissões para o processamento e transmissão de determinados\ndados pessoais. Um processamento de dados online só pode ser feito após a ativação dos dados móveis.", ro_RO="Vă rugăm să vă decideţi care din următoarele setări să fie activate pentru serviciile din autovehiculul dumneavoastră.\nReţineţi că sistemul dumneavoastră Infotainment necesită drepturi suplimentare pentru prelucrarea şi transmiterea\nanumitor date cu caracter personal. Prelucrarea online a datelor are loc numai când sunt active datele mobile.", ru_RU="Решите, какие из следующих настроек должны быть активированы для сервисов в вашем автомобиле. Обратите\nвнимание, что ваша информационно-развлекательная система может потребовать дополнительных разрешений на\nобработку и передачу определенных персональных данных. Обработка данных в режиме онлайн происходит только\nпри активированных мобильных данных.", sk_SK="Prosím, rozhodnite sa, ktoré z nasledujúcich nastavení sa má aktivovať pre služby vo vašom vozidle. Pamätajte na to, že\nváš informačný systém vozidla môže vyžadovať dodatočné oprávnenia na spracovanie a prenos určitých osobných údajov.\nOnline spracovanie údajov prebieha iba pri aktivácii mobilných dát.", sl_SI="Določite, katere od naslednjih nastavitev za storitve v vašem vozilu naj se aktivirajo. Upoštevajte, da vaš sistem\nInfotainment morda potrebuje dodatna pooblastila za obdelavo in prenos določenih osebnih podatkov. Spletna obdelava\npodatkov poteka samo pri aktivaciji mobilnih podatkov.", sr_RS="Odlučite koja od sledećih podešavanja za usluge u svom vozilu želite da aktivirate. Imajte na umu da su infotainment\nsistemu eventualno potrebna dodatna ovlašćenja za obradu i prenos određenih ličnih podataka. Onlajn obrada podataka\nvrši se samo kada su mobilni podaci aktivirani.", sv_SE="Välj vilka av följande inställningar för tjänsterna i din bil som ska aktiveras. Observera att ditt infotainmentsystem ev.\nbehöver ytterligare behörigheter för behandling och överföring av specifika personuppgifter. Behandling av data online\nsker endast när mobildata har aktiverats.", tr_TR="Lütfen aracındaki hizmetler için aşağıdaki ayarlardan hangilerinin etkinleştirilmesi gerektiğine karar ver. Bilgilendirici\nsisteminin, belirli kişisel verilerin işlenmesi ve iletilmesi için ek izinler gerektirebileceğini dikkate al. Çevrimiçi veri işleme\nsadece mobil verilerin etkinleştirilmesi durumunda gerçekleşir.", uk_UA="Вирішіть, які з наступних налаштувань мають бути активовані для служб у вашому автомобілі. Зверніть увагу, що\nваша інформаційно-командна система може зажадати додаткових дозволів на обробку та передачу певних\nперсональних даних. Обробка даних у режимі онлайн відбувається тільки за активованих мобільних даних.")
screen_content__privacy_ttdsg_description = TextObject(bs_BA="Pomozite nam da poboljšamo usluge i proizvode kompanije Audi. Uz Vašu saglasnost, Audi može pristupiti Vašem vozilu u\nsvrhe navedene u nastavku. Opoziv možete u svakom trenutku da izvršite u postavkama za zaštitu podataka. Prikupljanje\npodataka vrši se samo ako su mobilni podaci aktivirani.", cs_CZ="Pomozte nám zlepšovat služby a produkty společnosti Audi. S Vaším souhlasem může společnost Audi může níže\nuvedenými účely přistupovat k Vašemu vozidlu. Souhlas můžete kdykoli odvolat v nastaveních ochrany dat.\nShromažďování dat probíhá, jen když jsou mobilní data aktivována.", da_DK="Hjælp med at forbedre tjenester og produkter hos Audi. Med dit samtykke kan Audi få adgang til din bil til nedenstående\nformål. Du kan til enhver tid tilbagekalde det i databeskyttelsesindstillingerne. Onlinedatabehandling sker kun ved\naktivering af mobildata.", de_DE="Hilf mit, Dienste und Produkte bei Audi zu verbessern. Mit deiner Einwilligung kann Audi zu den unten genannten\nZwecken auf dein Fahrzeug zugreifen. Ein Widerruf ist jederzeit in den Datenschutzeinstellungen möglich. Eine\nDatenerhebungen erfolgt nur, wenn die mobilen Daten aktiviert sind.", el_GR="Βοηθήστε να βελτιωθούν οι υπηρεσίες και τα προϊόντα της Audi. Με τη συναίνεσή σας, η Audi μπορεί να έχει πρόσβαση στο\nόχημά σας, για τους αναφερόμενους παρακάτω σκοπούς. Η ανάκληση είναι εφικτή ανά πάσα στιγμή στις ρυθμίσεις\nπροστασίας δεδομένων. Η συλλογή δεδομένων λαμβάνει χώρα μόνον όταν είναι ενεργοποιημένα τα δεδομένα κινητής\nτηλεφωνίας.", en_GB="Help to improve Audi's products and services. With your consent, Audi can access your vehicle for the purposes specified\nbelow. You can withdraw your consent at any time in the privacy settings. Data collection is only performed when mobile\ndata is activated.", es_ES="Ayúdenos a mejorar nuestros servicios y productos. Con su consentimiento, Audi podrá acceder a su vehículo para cumplir\nlos objetivos que se indican más abajo. El consentimiento se puede revocar en todo momento en los ajustes de privacidad.\nSolo se recopilan datos con los datos móviles activados.", fi_FI="Auta Audia parantamaan palveluitaan ja tuotteitaan. Audilla on pääsy autoosi mainituissa tarkoituksissa, mikäli annat\nsiihen suostumuksesi. Voit milloin tahansa peruuttaa suostumuksesi tietosuoja-asetuksista. Tietoja kerätään vain, kun\nmobiilidata on aktivoitu.", fr_FR="Aidez-nous chez Audi à améliorer nos services et produits. Avec votre consentement, Audi peut accéder à votre véhicule\naux fins énoncées ci-dessous. Vous pouvez le révoquer à tout moment dans les réglages de la confidentialité. Le\ntraitement des données en ligne n'a lieu que lorsque les données mobiles sont activées.", hr_HR="Pomozite nam da poboljšamo Audijeve usluge i proizvode. Uz vaše odobrenje Audi može pristupiti vašem vozilu u dolje\nnavedene svrhe. Opoziv je moguć u svakom trenutku u postavkama zaštite podataka. Podaci se prikupljaju samo kada su\naktivirani mobilni podaci.", hu_HU="Segíts fejleszteni az Audi szolgáltatásait és termékeit! Az Audi az alábbiakban felsorolt célokra férhet hozzá járművedhez,\namennyiben hozzájárulsz. Az adatvédelmi beállításokban bármikor visszavonhatod a hozzájárulásodat. Az adatgyűjtésre\ncsak aktivált mobil adatoknál kerül sor.", it_IT="Ci aiuti a migliorare i servizi e i prodotti Audi. Con il Suo consenso, Audi può accedere alla Sua vettura per le finalità\nriportate di seguito. La revoca è possibile in qualsiasi momento nelle impostazioni per la protezione dati. La rilevazione di\ndati avviene solo quando i dati mobili sono attivati.", nl_NL="Help mee om diensten en producten van Audi te verbeteren. Met jouw toestemming kan Audi voor de hierna genoemde\ndoeleinden toegang krijgen tot jouw voertuig. Intrekking is altijd in de privacy-instellingen mogelijk. Gegevensverzameling\nvindt alleen plaats als mobiele data zijn geactiveerd.", no_NO="Hjelp oss å forbedre Audis tjenester og produkter. Hvis du gir samtykke til det, kan Audi få tilgang til bilen din for\nformålene nevnt under. Du kan når som helst trekke tilbake samtykket i personverninnstillingene. Datainnsamling skjer\nbare når mobildata er aktivert.", pl_PL="Pomóż nam doskonalić usługi i produkty Audi. W celach wymienionych poniżej, Audi może uzyskiwać dostęp do Twojego\npojazdu, jeśli wyrazisz na to zgodę. Możesz ją cofnąć w każdej chwili w ustawieniach polityki prywatności. Gromadzenie\ndanych odbywa się tylko przy włączonych danych mobilnych.", pt_PT="Ajuda a Audi a melhorar os serviços e os produtos. Dando a tua permissão a Audi pode aceder ao teu veículo com a\nfinalidade abaixo referida. Isto pode ser cancelado em qualquer momento nos ajustes da proteção de dados. O\nlevantamento dos dados só pode ser feito após a ativação dos dados móveis.", ro_RO="Ajutaţi la îmbunătăţirea serviciilor şi produselor la Audi. Cu acordul dumneavoastră, Audi poate accesa autovehiculul\ndumneavoastră în scopurile de mai jos. Puteţi revoca acordul dumneavoastră în orice moment, în setările de protecţia\ndatelor. Colectarea datelor are loc numai când sunt activate datele mobile.", ru_RU="Помочь улучшить сервисы и продукты Audi. С вашего согласия Audi может получить доступ к вашему автомобилю для\nуказанных ниже целей. Отзыв согласия возможен в любое время в настройках защиты данных. Сбор данных\nосуществляется только при активации мобильных данных.", sk_SK="Pomôžte zlepšiť služby a produkty v spoločnosti Audi. S vaším súhlasom môže Audi pristupovať k vášmu vozidlu na účely\nuvedené nižšie. Odvolanie je možné kedykoľvek v nastaveniach ochrany údajov. Získavanie údajov prebieha iba vtedy, keď\nsú aktivované mobilné dáta.", sl_SI="Pomagajte izboljšati storitve in produkte znamke Audi. Z vašim soglasjem lahko Audi za spodaj navedene namene dostopa\ndo vašega vozila. Soglasje lahko kadar koli prekličete v nastavitvah zasebnosti. Zbiranje podatkov poteka samo, ko so\nmobilni podatki aktivirani.", sr_RS="Pomozite nam da poboljšamo usluge i proizvode kompanije Audi. Uz vašu saglasnost, Audi može da pristupi vašem vozilu\nu svrhe navedene u nastavku. Opoziv možete u svakom trenutku da izvršite u podešavanjima za zaštitu podataka.\nPrikupljanje podataka se vrši samo ako su mobilni podaci aktivirani.", sv_SE="Hjälp oss att förbättra Audis tjänster och produkter. Med ditt samtycke kan Audi komma åt ditt fordon för nedanstående\nsyften. Du kan när som helst dra tillbaka ditt samtycke i integritetsinställningarna. Datainsamling sker endast när\nmobildata har aktiverats.", tr_TR="Audi'de hizmetlerin ve ürünlerin iyileştirilmesine yardımcı ol. Onay vermen ile Audi, aşağıda belirtilen amaçlar\ndoğrultusunda aracına erişebilir. Veri koruma ayarlarında her zaman bir iptal mümkündür. Veri toplama sadece mobil veri\netkinleştirilmişse gerçekleşir.", uk_UA="Допомогти поліпшити служби та продукти Audi. З вашої згоди Audi може отримати доступ до вашого автомобіля для\nзазначених нижче цілей. Відкликання згоди можливе в будь-який час у налаштуваннях захисту даних. Збір даних\nздійснюється тільки при активації мобільних даних.")
screen_content__pso_android_pin = TextObject(bs_BA="Kreirajte PIN sa najmanje 4 cifre.", cs_CZ="Určete PIN s nejméně 4 číslicemi.", da_DK="Definer en pinkode på mindst fire cifre.", de_DE="Lege eine PIN mit mindestens 4\nZiffern fest.", el_GR="Καθορίστε ένα PIN με τουλάχιστον 4 χαρακτήρες.", en_GB="Please specify a PIN with at least 4 digits.", es_ES="Defina un PIN con al menos 4 dígitos.", fi_FI="Aseta vähintään nelinumeroinen PIN-koodi.", fr_FR="Définissez un code PIN d'au moins 4 chiffres.", hr_HR="Kreirajte PIN s najmanje 4 znamenke.", hu_HU="Állíts be egy legalább 4 jegyű PIN-kódot.", it_IT="Impostare un PIN con almeno 4 cifre.", nl_NL="Maak een pincode met minimaal 4 cijfers aan.", no_NO="Lag en PIN-kode med minst fire sifre.", pl_PL="Zdefiniuj co najmniej 4-cyfrowy kod PIN.", pt_PT="Define um PIN com 4 digitos no mínimo.", ro_RO="Stabiliţi un cod PIN cu cel puţin 4 cifre.", ru_RU="Установите PIN длиной не менее 4 символов.", sk_SK="Stanovte PIN s najmenej 4 znakmi.", sl_SI="Določite PIN-kodo z najmanj 4 številkami.", sr_RS="Kreirajte PIN sa najmanje 4 cifre.", sv_SE="Fastställ en PIN med minst 4 tecken.", tr_TR="En az 4 karakterden oluşan bir PIN belirle.", uk_UA="Установіть PIN-код завдовжки щонайменше 4 символи.")
