screen_content__pso_security_already_selected_first_part_android = TextObject(bs_BA="Vaša trenutna PIN zaštita: PIN vozila", cs_CZ="Vaše aktuální ochrana PIN: PIN vozidla", da_DK="Din aktuelle pinkodebeskyttelse: Bilpinkode", de_DE="Dein aktueller PIN-Schutz: Fahrzeug-PIN", el_GR="Η τρέχουσα προστασία PIN σας: PIN οχήματος", en_GB="Your current PIN protection: vehicle PIN", es_ES="Protección con PIN actual: PIN del vehículo", fi_FI="Nykyinen PIN-suojauksesi: auton PIN-koodi", fr_FR="Votre protection actuelle par code PIN: code PIN du véhicule", hr_HR="Vaš trenutačni PIN: PIN vozila", hu_HU="Jelenlegi PIN-kód védelmed: jármű PIN-kód", it_IT="Attuale protezione con PIN: PIN vettura", nl_NL="Je huidige pincodebescherming: Voertuigpincode", no_NO="Nåværende PIN-beskyttelse: Bilens PIN-kode", pl_PL="Twoje aktualne zabezpieczenie kodem PIN: kod PIN pojazdu", pt_PT="O teu PIN de proteção atual: PIN do veículo", ro_RO="PIN-ul dvs. de protecţie actual: PIN autovehicul", ru_RU="Ваш текущий PIN-код защиты: PIN-код автомобиля", sk_SK="Vaša aktuálna ochrana PIN: PIN vozidla", sl_SI="Vaša trenutna zaščita s PIN-kodo: PIN-koda vozila", sr_RS="Vaša trenutna PIN zaštita: PIN vozila", sv_SE="Ditt aktuella PIN-skydd: fordons-PIN", tr_TR="Mevcut PIN koruman: Araç PIN'i", uk_UA="Ваш поточний PIN-код захисту: PIN-код автомобіля")
