screen_content__pso_security_already_selected_first_part_oem = TextObject(bs_BA="Vaša trenutna PIN zaštita: myAudi PIN", cs_CZ="Vaše aktuální ochrana PIN: myAudi PIN", da_DK="Din aktuelle pinkodebeskyttelse: myAudi-pinkode", de_DE="Dein aktueller PIN-Schutz: myAudi PIN", el_GR="Η τρέχουσα προστασία PIN σας: myAudi PIN", en_GB="Your current PIN protection: myAudi PIN", es_ES="Protección con PIN actual: PIN myAudi", fi_FI="Nykyinen PIN-suojauksesi: myAudi-PIN", fr_FR="Votre protection actuelle par code PIN: code PIN myAudi", hr_HR="Vaš trenutačni PIN: myAudi PIN", hu_HU="Jelenlegi PIN-kód védelmed: myAudi PIN", it_IT="Attuale protezione con PIN: PIN myAudi", nl_NL="Je huidige pincodebescherming: myAudi PIN", no_NO="Nåværende PIN-beskyttelse: myAudi-PIN", pl_PL="Twoje aktualne zabezpieczenie kodem PIN: kod PIN myAudi", pt_PT="O teu PIN de proteção atual: PIN myAudi", ro_RO="PIN-ul dvs. de protecţie actual: PIN myAudi", ru_RU="Ваша текущая защита с помощью PIN-кода: myAudi PIN", sk_SK="Vaša aktuálna ochrana PIN: myAudi PIN", sl_SI="Vaša trenutna zaščita s PIN-kodo: PIN-koda myAudi", sr_RS="Vaša trenutna PIN zaštita: myAudi PIN", sv_SE="Ditt aktuella PIN-skydd: myAudi-PIN", tr_TR="Mevcut PIN koruman: myAudi PIN", uk_UA="Ваш поточний PIN-код захисту: PIN-код myAudi")
screen_content__pso_security_already_selected_second_part = TextObject(bs_BA="PIN zaštita može se promijeniti u postavkama.", cs_CZ="Ochranu PIN můžete změnit v nastaveních.", da_DK="Pinkodebeskyttelsen kan ændres i indstillingerne.", de_DE="Der PIN-Schutz kann in den Einstellungen geändert werden.", el_GR="Η προστασία PIN μπορεί να αλλάξει στις ρυθμίσεις.", en_GB="The PIN protection can be changed in the settings.", es_ES="La protección con PIN se puede modificar en los ajustes.", fi_FI="PIN-suojausta voidaan muuttaa asetuksista.", fr_FR="Vous pouvez modifier la protection par code PIN dans les réglages.", hr_HR="PIN se može promijeniti u postavkama.", hu_HU="PIN-kód védelmed a beállításokban módosítható.", it_IT="È possibile modificare la protezione con PIN nelle impostazioni.", nl_NL="Je pincode kan worden gewijzigd in de instellingen.", no_NO="Du kan endre PIN-beskyttelsen i innstillingene.", pl_PL="Zabezpieczenie kodem PIN można zmienić w ustawieniach.", pt_PT="O PIN de proteção pode ser alterado nos ajustes.", ro_RO="Protecţia PIN poate fi modificată în setări.", ru_RU="PIN-код можно изменить в настройках.", sk_SK="Ochranu kódom PIN je možné zmeniť v nastaveniach.", sl_SI="Zaščito s PIN-kodo lahko spremenite v nastavitvah.", sr_RS="PIN zaštita može da se promeni u podešavanjima.", sv_SE="PIN-skyddet kan ändras i inställningarna.", tr_TR="PIN koruması ayarlardan değiştirilebilir.", uk_UA="PIN-код можна змінити в налаштуваннях.")
screen_content__speech_description = TextObject(bs_BA="Uz pomoć Audi assistant-a možete glasovno upravljati brojnim funkcijama u vozilu. Audi assistant daje proaktivne\nprijedloge i rutine u odgovarajućim situacijama i u potrebnom obimu.", cs_CZ="Za pomoci Audi assistant můžete obsluhovat mnohé funkce ve vozidle hlasově. Audi assistant udílí proaktivní návrhy a\nrutiny ve správných situacích a v potřebném rozsahu.", da_DK="Ved hjælp af Audi assistant kan du stemmebetjene mange funktioner i bilen. Audi assistant kommer med proaktive forslag\nog rutiner til dig i de rigtige situationer og i det nødvendige omfang.", de_DE="Mit Hilfe des Audi assistant kannst du viele Funktionen im Fahrzeug per Sprache bedienen. Der Audi assistant unterbreitet\ndir proaktive Vorschläge und Routinen in den richtigen Situationen und im benötigten Umfang.", el_GR="Με τη βοήθεια της Audi assistant μπορείτε να χειριστείτε φωνητικά πολλές λειτουργίες στο όχημα. Η Audi assistant σας\nυποβάλλει προδραστικές προτάσεις και ρουτίνες στις σωστές καταστάσεις και στην απαιτούμενη έκταση.", en_GB="You can operate lots of functions in the vehicle by voice with the Audi assistant. The Audi assistant makes proactive\nsuggestions and offers you routines in the right situations according to your needs.", es_ES="Con ayuda del Audi assistant puede controlar por voz muchas funciones del vehículo. El Audi assistant le propondrá rutinas\ny sugerencias proactivas en determinadas situaciones y en la medida necesaria.", fi_FI="Audi assistantin avulla voit käyttää monia toimintoja autossa puheen avulla. Audi assistant ehdottaa ennakoivia ehdotuksia\nja rutiineja oikeissa tilanteissa ja tarvittavassa laajuudessa.", fr_FR="L'Audi assistant vous permet d'utiliser de nombreuses fonctions dans le véhicule au moyen des commandes vocales. L'Audi\nassistant vous soumet de manière mesurée des suggestions proactives et des routines dans les situations adéquates.", hr_HR="Pomoću Audi assistanta velikim brojem funkcija u vozilu možete rukovati govorom. Audi assistant proaktivno daje\nprijedloge i predlaže rutine u pravim situacijama i u potrebnom opsegu.", hu_HU="Az Audi assistant segítségével számos funkciót vezérelhetsz a járműben hanggal. Az Audi assistant proaktív javaslatokat és\nrutinokat ad a megfelelő helyzetekben és a szükséges mértékben.", it_IT="Grazie all'Audi assistant è possibile eseguire molte funzioni a bordo della vettura tramite comandi vocali. L'Audi assistant\nsuggerisce proposte proattive e routine nelle situazioni giuste e nella misura necessaria.", nl_NL="Met behulp van de Audi assistant kun je veel functies in het voertuig met spraak bedienen.De Audi assistent geeft je\nproactief suggesties en routines in de juiste situaties in in de vereiste mate.", no_NO="Med Audi assistant kan du styre mange funksjoner i bilen med talekommandoer. Audi assistant kommer med proaktive\nforslag og kan lage situasjonsbetingede rutiner.", pl_PL="Z pomocą Audi assistant można obsługiwać głosowo wiele funkcji w pojeździe. Audi assistant dostarcza proaktywne\nsugestie i rutyny w odpowiednich sytuacjach i w wymaganym zakresie.", pt_PT="Com o auxílio do Audi assistant podes controlar muitas funções no veículo através da voz. O Audi assistant dá-te\nrecomendações proativas e rotinas nas situações corretas e à medida das necessidades.", ro_RO="Cu Audi assistant puteţi opera multe funcţii din autovehicul prin comandă vocală. Audi assistant vă oferă propuneri\nproactive şi rutine în situaţiile potrivite şi în măsura necesară.", ru_RU="С помощью Audi assistant вы можете управлять многими функциями автомобиля голосом. Audi assistant\nпредоставляет вам проактивные рекомендации и стандартные действия в нужных ситуациях и в необходимом объеме.", sk_SK="Pomocou Audi assistant môžete ovládať mnoho funkcií vozidla hlasom. Audi assistant ti ponúka proaktívne návrhy a rutiny\nv správnych situáciách a v potrebnom rozsahu.", sl_SI="S pomočjo sistema Audi assistant lahko glasovno upravljate številne funkcije v vozilu. Audi assistant vam proaktivne\npredloge in rutinske postopke posreduje v pravih situacijah in v potrebnem obsegu.", sr_RS="Uz pomoć Audi assistant-a, brojnim funkcijama u vozilu možete da upravljate putem govora. Audi assistant vam prikazuje\nproaktivne predloge i rutine u odgovarajućim situacijama i u neophodnom ospegu.", sv_SE="Med hjälp av Audi assistant kan du röststyra flera funktioner i bilen. Audi assistant erbjuder dig proaktiva förslag och\nrutiner i rätt situationer och i den omfattning som behövs.", tr_TR="Audi assistant'ın yardımıyla araçtaki birçok fonksiyonu sesli komut ile kullanabilirsin. Audi assistant sana doğru durumlarda\nve gerektiği ölçüde proaktif öneriler ve rutinler sunar.", uk_UA="За допомогою Audi assistant ви можете керувати багатьма функціями автомобіля голосом. Audi assistant надає вам\nпроактивні пропозиції та стандартні дії в потрібних ситуаціях і в необхідному обсязі.")
screen_content__speech_description_minimal = TextObject(cs_CZ="Hlasovým ovládáním můžete hlasem obsluhovat různé funkce jako rádio nebo telefon", da_DK="Med stemmebetjeningsfunktionen kan du stemmebetjene forskellige funktioner som fx radio eller telefon.", de_DE="Mit der Sprachbedienung können verschiedene Funktionen, wie Radio oder Telefon, per Sprache bedient werden", el_GR="Με τον φωνητικό χειρισμό μπορεί να γίνει χειρισμός διαφόρων λειτουργιών, όπως ραδιόφωνο ή τηλέφωνο", en_GB="You can use speech control to operate various functions by voice, such as the radio or the telephone.", es_ES="El manejo por voz le permite controlar diferentes funciones, como la radio o el teléfono", fi_FI="Puheohjauksella voi puheen avulla käyttää erilaisia toimintoja, kuten radiota tai puhelinta", fr_FR="Le système à commande vocale vous permet d'utiliser différentes fonctions telles que la radio ou le téléphone au moyen\ndes commandes vocales.", hu_HU="A beszédvezérléssel különböző funkciók, például a rádió vagy a telefon, hanggal is működtethetők", it_IT="Con il sistema di comando vocale è possibile comandare con la voce diverse funzioni, come radio o telefono", nl_NL="Met de spraakbediening kunnen verschillende functies, zoals radio of telefoon, met spraak worden bediend", no_NO="Med stemmestyringen kan du styre ulike funksjoner, for eksempel radio og telefon, med stemmen", pl_PL="Obsługa głosowa pozwala obsługiwać głosem rozmaite funkcje, jak radio czy telefon", pt_PT="Através do comando por voz é possível acionar várias funções, como o rádio ou o telefone, com a voz", ru_RU="С помощью голосового управления можно управлять различными функциями, такими как радио или телефон, с\nпомощью голоса", sv_SE="Med röststyrningen kan olika funktioner som t.ex. radio eller telefon styras med rösten", tr_TR="Sesle kontrol ile, radyo veya telefon gibi çeşitli fonksiyonlar konuşarak kumanda edilebilir")
screen_content__speech_description_no_smart_system = TextObject(cs_CZ="Za pomoci Audi assistanta můžete obsluhovat mnohé funkce ve vozidle hlasově.", da_DK="Ved hjælp af Audi assistant kan du stemmebetjene mange funktioner i bilen.", de_DE="Mit Hilfe des Audi assistant kannst du viele Funktionen im Fahrzeug per Sprache bedienen.", el_GR="Με τη βοήθεια της Audi assistant μπορείτε να χειριστείτε φωνητικά πολλές λειτουργίες στο όχημα.", en_GB="You can operate lots of functions in the vehicle by voice with the Audi assistant.", es_ES="Con ayuda del Audi assistant puede controlar por voz muchas funciones del vehículo.", fi_FI="Audi assistantin avulla voit käyttää monia toimintoja autossa puheen avulla.", fr_FR="L'Audi assistant vous permet d'utiliser de nombreuses fonctions dans le véhicule au moyen des commandes vocales.", hu_HU="Az Audi assistant segítségével számos funkciót vezérelhetsz a járműben hanggal.", it_IT="Grazie all'Audi assistant è possibile eseguire molte funzioni a bordo della vettura tramite comandi vocali.", nl_NL="Met behulp van Audi assistant kun je veel functies in het voertuig met spraak bedienen.", no_NO="Med Audi assistant kan du styre mange funksjoner i bilen med stemmen.", pl_PL="Za pomocą funkcji Audio assistant możesz obsługiwać głosowo wiele funkcji samochodu.", pt_PT="Com o auxílio do Audi assistant podes controlar através da voz muitas funções no veículo.", ru_RU="С помощью Audi Аssistant вы можете управлять многими функциями автомобиля с помощью голоса.", sv_SE="Med hjälp av Audi assistant kan du röststyra flera funktioner i fordonet.", tr_TR="Audi assistant'ın yardımıyla araçtaki birçok fonksiyonu sesli komut ile kullanabilirsin.")
